    {"offset": {"line": 300, "column": 0}, "map": {"version":3,"sources":["file:///C:/HMF/Frontend/lib/api/email.ts"],"sourcesContent":["const BASE_URL = \"http://localhost:8000\";\r\n\r\nexport async function analyzeEmail(data: {\r\n  sender: string;\r\n  subject: string;\r\n  body: string;\r\n  with_llm_explanation?: boolean;\r\n}) {\r\n  const res = await fetch(`${BASE_URL}/text/email/analyze/extension`, {\r\n    method: \"POST\",\r\n    headers: { \"Content-Type\": \"application/json\" },\r\n    credentials: \"include\",\r\n    body: JSON.stringify(data),\r\n  });\r\n  if (!res.ok) throw new Error(await res.text());\r\n  return res.json();\r\n}\r\n"],"names":[],"mappings":";;;;AAAA,MAAM,WAAW;AAEV,eAAe,aAAa,IAKlC;IACC,MAAM,MAAM,MAAM,MAAM,GAAG,SAAS,6BAA6B,CAAC,EAAE;QAClE,QAAQ;QACR,SAAS;YAAE,gBAAgB;QAAmB;QAC9C,aAAa;QACb,MAAM,KAAK,SAAS,CAAC;IACvB;IACA,IAAI,CAAC,IAAI,EAAE,EAAE,MAAM,IAAI,MAAM,MAAM,IAAI,IAAI;IAC3C,OAAO,IAAI,IAAI;AACjB"}},
    {"offset": {"line": 321, "column": 0}, "map": {"version":3,"sources":["file:///C:/HMF/Frontend/lib/api/url.ts"],"sourcesContent":["const BASE_URL = \"http://localhost:8000\";\r\n\r\nexport async function analyzeUrl(data: {\r\n  url: string;\r\n  with_llm_explanation?: boolean;\r\n}) {\r\n  const res = await fetch(`${BASE_URL}/url/analyze`, {\r\n    method: \"POST\",\r\n    headers: { \"Content-Type\": \"application/json\" },\r\n    credentials: \"include\",\r\n    body: JSON.stringify(data),\r\n  });\r\n  if (!res.ok) throw new Error(await res.text());\r\n  return res.json();\r\n}\r\n"],"names":[],"mappings":";;;;AAAA,MAAM,WAAW;AAEV,eAAe,WAAW,IAGhC;IACC,MAAM,MAAM,MAAM,MAAM,GAAG,SAAS,YAAY,CAAC,EAAE;QACjD,QAAQ;QACR,SAAS;YAAE,gBAAgB;QAAmB;QAC9C,aAAa;QACb,MAAM,KAAK,SAAS,CAAC;IACvB;IACA,IAAI,CAAC,IAAI,EAAE,EAAE,MAAM,IAAI,MAAM,MAAM,IAAI,IAAI;IAC3C,OAAO,IAAI,IAAI;AACjB"}},
    {"offset": {"line": 342, "column": 0}, "map": {"version":3,"sources":["file:///C:/HMF/Frontend/lib/api/voice.ts"],"sourcesContent":["const BASE_URL = \"http://localhost:8000\";\r\n\r\nexport async function analyzeVoice(file: File) {\r\n  const form = new FormData();\r\n  form.append(\"file\", file);\r\n\r\n  const res = await fetch(`${BASE_URL}/voice/analyse`, {\r\n    method: \"POST\",\r\n    credentials: \"include\",\r\n    body: form,\r\n  });\r\n  if (!res.ok) throw new Error(await res.text());\r\n  return res.json();\r\n}\r\n"],"names":[],"mappings":";;;;AAAA,MAAM,WAAW;AAEV,eAAe,aAAa,IAAU;IAC3C,MAAM,OAAO,IAAI;IACjB,KAAK,MAAM,CAAC,QAAQ;IAEpB,MAAM,MAAM,MAAM,MAAM,GAAG,SAAS,cAAc,CAAC,EAAE;QACnD,QAAQ;QACR,aAAa;QACb,MAAM;IACR;IACA,IAAI,CAAC,IAAI,EAAE,EAAE,MAAM,IAAI,MAAM,MAAM,IAAI,IAAI;IAC3C,OAAO,IAAI,IAAI;AACjB"}},
    {"offset": {"line": 362, "column": 0}, "map": {"version":3,"sources":["file:///C:/HMF/Frontend/lib/api/attachment.ts"],"sourcesContent":["const BASE_URL = \"http://localhost:8000\";\r\n\r\nexport async function analyzeAttachment(\r\n  file: File,\r\n  withLlmExplanation = false\r\n) {\r\n  const form = new FormData();\r\n  form.append(\"file\", file);\r\n  form.append(\"with_llm_explanation\", withLlmExplanation ? \"true\" : \"false\");\r\n\r\n  const res = await fetch(`${BASE_URL}/attachment/analyze`, {\r\n    method: \"POST\",\r\n    credentials: \"include\",\r\n    body: form,\r\n  });\r\n  if (!res.ok) throw new Error(await res.text());\r\n  return res.json();\r\n}\r\n"],"names":[],"mappings":";;;;AAAA,MAAM,WAAW;AAEV,eAAe,kBACpB,IAAU,EACV,qBAAqB,KAAK;IAE1B,MAAM,OAAO,IAAI;IACjB,KAAK,MAAM,CAAC,QAAQ;IACpB,KAAK,MAAM,CAAC,wBAAwB,qBAAqB,SAAS;IAElE,MAAM,MAAM,MAAM,MAAM,GAAG,SAAS,mBAAmB,CAAC,EAAE;QACxD,QAAQ;QACR,aAAa;QACb,MAAM;IACR;IACA,IAAI,CAAC,IAAI,EAAE,EAAE,MAAM,IAAI,MAAM,MAAM,IAAI,IAAI;IAC3C,OAAO,IAAI,IAAI;AACjB"}},
    {"offset": {"line": 383, "column": 0}, "map": {"version":3,"sources":["file:///C:/HMF/Frontend/components/AnalysisResult.tsx"],"sourcesContent":["\"use client\"\r\n\r\nimport { useEffect, useRef, type ReactNode } from \"react\"\r\n\r\n// ─── Shape definitions ──────────────────────────────────────────────────────\r\n\r\ninterface Prediction {\r\n  label?: string\r\n  confidence?: number\r\n}\r\n\r\ninterface FraudReport {\r\n  risk_score?: number\r\n  is_fraud?: boolean\r\n  system_logic?: string\r\n  red_flags?: string[]\r\n}\r\n\r\ninterface VoiceAnalysis {\r\n  result?: string\r\n  confidence?: number\r\n}\r\n\r\nexport interface AnalysisData {\r\n  request_id?: string\r\n  // scores\r\n  risk_score?: number\r\n  confidence?: number\r\n  phishing_probability?: number\r\n  risk_level?: string\r\n  // classification\r\n  fraud_type?: string\r\n  final_verdict?: string\r\n  // text signals\r\n  flags?: string[]\r\n  explanation?: string\r\n  llm_explanation?: string\r\n  llm_confidence?: number\r\n  // sub-scores\r\n  nlp_score?: number\r\n  similarity_score?: number\r\n  stylometry_score?: number\r\n  url_risk_score?: number\r\n  urgency_score?: number\r\n  // nested shapes (voice / attachment)\r\n  prediction?: Prediction\r\n  fraud_report?: FraudReport\r\n  voice_analysis?: VoiceAnalysis\r\n  [key: string]: unknown\r\n}\r\n\r\n// ─── Normalize heterogeneous API shapes ─────────────────────────────────────\r\n\r\ntype RiskLevel = \"LOW\" | \"MEDIUM\" | \"HIGH\"\r\n\r\nfunction deriveLevel(score: number | null, provided?: string): RiskLevel | null {\r\n  if (provided) {\r\n    const u = provided.toUpperCase()\r\n    if (u === \"LOW\" || u === \"MEDIUM\" || u === \"HIGH\") return u as RiskLevel\r\n  }\r\n  if (score === null) return null\r\n  if (score < 0.3) return \"LOW\"\r\n  if (score <= 0.7) return \"MEDIUM\"\r\n  return \"HIGH\"\r\n}\r\n\r\nfunction normalize(r: AnalysisData) {\r\n  const riskScore =\r\n    typeof r.risk_score === \"number\" ? r.risk_score\r\n    : typeof r.fraud_report?.risk_score === \"number\" ? r.fraud_report!.risk_score!\r\n    : typeof r.phishing_probability === \"number\" ? r.phishing_probability\r\n    : null\r\n\r\n  const confidence =\r\n    typeof r.confidence === \"number\" ? r.confidence\r\n    : typeof r.llm_confidence === \"number\" ? r.llm_confidence\r\n    : null\r\n\r\n  const fraudType =\r\n    typeof r.fraud_type === \"string\" ? r.fraud_type\r\n    : typeof r.final_verdict === \"string\" ? r.final_verdict\r\n    : typeof r.fraud_report?.is_fraud === \"boolean\"\r\n      ? (r.fraud_report!.is_fraud ? \"fraud\" : \"clean\")\r\n    : null\r\n\r\n  const predLabel =\r\n    r.prediction?.label\r\n    ?? r.voice_analysis?.result\r\n    ?? null\r\n\r\n  const predConfidence =\r\n    typeof r.prediction?.confidence === \"number\" ? r.prediction!.confidence!\r\n    : typeof r.voice_analysis?.confidence === \"number\" ? r.voice_analysis!.confidence!\r\n    : null\r\n\r\n  const flags: string[] = [\r\n    ...(Array.isArray(r.flags) ? (r.flags as string[]) : []),\r\n    ...(Array.isArray(r.fraud_report?.red_flags) ? r.fraud_report!.red_flags! : []),\r\n  ]\r\n\r\n  const explanation =\r\n    (typeof r.llm_explanation === \"string\" && r.llm_explanation.trim())\r\n      ? r.llm_explanation.trim()\r\n    : (typeof r.explanation === \"string\" && r.explanation.trim())\r\n      ? r.explanation.trim()\r\n    : (typeof r.fraud_report?.system_logic === \"string\" && r.fraud_report!.system_logic!.trim())\r\n      ? r.fraud_report!.system_logic!.trim()\r\n    : null\r\n\r\n  const riskLevel = deriveLevel(riskScore, r.risk_level)\r\n\r\n  const nlpScore = typeof r.nlp_score === \"number\" ? r.nlp_score : null\r\n  const simScore = typeof r.similarity_score === \"number\" ? r.similarity_score : null\r\n  const styloScore = typeof r.stylometry_score === \"number\" ? r.stylometry_score : null\r\n  const urlRisk = typeof r.url_risk_score === \"number\" ? r.url_risk_score : null\r\n  const urgency = typeof r.urgency_score === \"number\" ? r.urgency_score : null\r\n\r\n  const hasAdvanced = [nlpScore, simScore, styloScore, urlRisk, urgency].some((v) => v !== null)\r\n\r\n  const reqId = typeof r.request_id === \"string\" ? r.request_id : null\r\n\r\n  const SAFE_LABELS = new Set([\"safe\", \"clean\", \"ham\", \"real (bonafide)\"])\r\n  const isThreat = !!fraudType && !SAFE_LABELS.has(fraudType.toLowerCase())\r\n  const isPredThreat = !!predLabel && !SAFE_LABELS.has(predLabel.toLowerCase())\r\n\r\n  return {\r\n    riskScore,\r\n    riskLevel,\r\n    confidence,\r\n    fraudType,\r\n    predLabel,\r\n    predConfidence,\r\n    flags,\r\n    explanation,\r\n    nlpScore,\r\n    simScore,\r\n    styloScore,\r\n    urlRisk,\r\n    urgency,\r\n    hasAdvanced,\r\n    reqId,\r\n    isThreat,\r\n    isPredThreat,\r\n  }\r\n}\r\n\r\n// ─── Formatters ──────────────────────────────────────────────────────────────\r\n\r\nconst pct = (n: number | null) => (n === null ? \"—\" : `${(n * 100).toFixed(0)}%`)\r\nconst f2  = (n: number | null) => (n === null ? \"—\" : n.toFixed(2))\r\n\r\n// ─── Risk visual tokens ──────────────────────────────────────────────────────\r\n\r\nconst RISK_TEXT: Record<RiskLevel, string> = {\r\n  LOW:    \"text-foreground/35\",\r\n  MEDIUM: \"text-accent\",\r\n  HIGH:   \"text-destructive\",\r\n}\r\n\r\nconst RISK_BORDER: Record<RiskLevel, string> = {\r\n  LOW:    \"border-border/20\",\r\n  MEDIUM: \"border-accent/25\",\r\n  HIGH:   \"border-destructive/35\",\r\n}\r\n\r\n// ─── Internal atoms ──────────────────────────────────────────────────────────\r\n\r\nfunction Divider() {\r\n  return <div className=\"border-b border-border/10\" />\r\n}\r\n\r\nfunction SectionLabel({ children }: { children: ReactNode }) {\r\n  return (\r\n    <p className=\"font-mono text-[9px] uppercase tracking-[0.45em] text-muted-foreground/40 mb-4\">\r\n      {children}\r\n    </p>\r\n  )\r\n}\r\n\r\nfunction CoreMetric({ label, value, accent = false }: { label: string; value: string; accent?: boolean }) {\r\n  return (\r\n    <div>\r\n      <p className=\"font-mono text-[8px] uppercase tracking-[0.35em] text-muted-foreground/35 mb-1.5\">\r\n        {label}\r\n      </p>\r\n      <p className={`font-mono text-sm tracking-[0.03em] ${accent ? \"text-accent\" : \"text-foreground/75\"}`}>\r\n        {value}\r\n      </p>\r\n    </div>\r\n  )\r\n}\r\n\r\nfunction TinySignal({ label, value }: { label: string; value: string }) {\r\n  return (\r\n    <div className=\"flex items-baseline gap-1.5\">\r\n      <span className=\"font-mono text-[8px] uppercase tracking-[0.25em] text-muted-foreground/25\">\r\n        {label}\r\n      </span>\r\n      <span className=\"font-mono text-[10px] text-muted-foreground/35\">{value}</span>\r\n    </div>\r\n  )\r\n}\r\n\r\n// ─── Main component ───────────────────────────────────────────────────────────\r\n\r\nexport function AnalysisResult({ data }: { data: AnalysisData }) {\r\n  const rootRef = useRef<HTMLDivElement>(null)\r\n  const d = normalize(data)\r\n\r\n  // Smooth entrance — no library required\r\n  useEffect(() => {\r\n    const el = rootRef.current\r\n    if (!el) return\r\n    el.style.opacity = \"0\"\r\n    el.style.transform = \"translateY(10px)\"\r\n    const raf = requestAnimationFrame(() => {\r\n      el.style.transition =\r\n        \"opacity 0.55s cubic-bezier(0.16,1,0.3,1), transform 0.55s cubic-bezier(0.16,1,0.3,1)\"\r\n      el.style.opacity = \"1\"\r\n      el.style.transform = \"translateY(0)\"\r\n    })\r\n    return () => cancelAnimationFrame(raf)\r\n  }, [])\r\n\r\n  const riskText   = d.riskLevel ? RISK_TEXT[d.riskLevel]   : \"text-foreground/25\"\r\n  const riskBorder = d.riskLevel ? RISK_BORDER[d.riskLevel] : \"border-border/15\"\r\n\r\n  return (\r\n    <div ref={rootRef} className={`border ${riskBorder} mt-8`}>\r\n\r\n      {/* ── Header ─────────────────────────────────────────────────────────── */}\r\n      <div className=\"flex items-center justify-between px-5 py-3\">\r\n        <span className=\"font-mono text-[9px] uppercase tracking-[0.45em] text-muted-foreground/40\">\r\n          Threat Assessment\r\n        </span>\r\n        {d.reqId && (\r\n          <span className=\"font-mono text-[8px] text-muted-foreground/20 tracking-[0.15em]\">\r\n            {d.reqId.slice(0, 8).toUpperCase()}\r\n          </span>\r\n        )}\r\n      </div>\r\n      <Divider />\r\n\r\n      {/* ── 1. Primary Signal ───────────────────────────────────────────────── */}\r\n      <div className=\"px-5 py-8\">\r\n        <SectionLabel>Risk Level</SectionLabel>\r\n        <div className=\"flex items-end gap-3\">\r\n          {d.riskLevel === \"HIGH\" && (\r\n            <span className=\"inline-block w-1.5 h-1.5 bg-destructive self-center shrink-0 animate-pulse mb-1\" />\r\n          )}\r\n          {d.riskLevel === \"MEDIUM\" && (\r\n            <span className=\"inline-block w-1.5 h-1.5 bg-accent self-center shrink-0 mb-1\" />\r\n          )}\r\n          <span\r\n            className={`font-[var(--font-bebas)] text-6xl md:text-7xl leading-none tracking-tight ${riskText}`}\r\n          >\r\n            {d.riskLevel ?? \"UNKNOWN\"}\r\n          </span>\r\n          {d.riskScore !== null && (\r\n            <span className=\"font-mono text-[10px] text-muted-foreground/30 mb-1.5 tracking-[0.1em]\">\r\n              {pct(d.riskScore)} raw\r\n            </span>\r\n          )}\r\n        </div>\r\n      </div>\r\n      <Divider />\r\n\r\n      {/* ── 2. Core Metrics ─────────────────────────────────────────────────── */}\r\n      <div className=\"px-5 py-6\">\r\n        <SectionLabel>Core Metrics</SectionLabel>\r\n        <div className=\"grid grid-cols-2 md:grid-cols-4 gap-x-6 gap-y-5\">\r\n          <CoreMetric label=\"Risk Score\"  value={pct(d.riskScore)} />\r\n          <CoreMetric label=\"Confidence\"  value={pct(d.confidence)} />\r\n          <CoreMetric\r\n            label=\"Prediction\"\r\n            value={d.predLabel ? d.predLabel.toUpperCase() : \"—\"}\r\n            accent={d.isPredThreat}\r\n          />\r\n          <CoreMetric\r\n            label=\"Fraud Type\"\r\n            value={d.fraudType ? d.fraudType.toUpperCase() : \"—\"}\r\n            accent={d.isThreat}\r\n          />\r\n        </div>\r\n      </div>\r\n      <Divider />\r\n\r\n      {/* ── 3. Active Signals ───────────────────────────────────────────────── */}\r\n      <div className=\"px-5 py-6\">\r\n        <SectionLabel>\r\n          {d.flags.length > 0 ? `Active Signals [${d.flags.length}]` : \"Active Signals\"}\r\n        </SectionLabel>\r\n        {d.flags.length > 0 ? (\r\n          <div className=\"flex flex-wrap gap-2\">\r\n            {d.flags.map((flag, i) => (\r\n              <span\r\n                key={i}\r\n                className=\"font-mono text-[9px] uppercase tracking-[0.15em] border border-border/20 px-2.5 py-1 text-muted-foreground/50\"\r\n              >\r\n                {flag.replace(/_/g, \" \")}\r\n              </span>\r\n            ))}\r\n          </div>\r\n        ) : (\r\n          <p className=\"font-mono text-[10px] text-muted-foreground/25 tracking-[0.1em]\">\r\n            No active threat indicators\r\n          </p>\r\n        )}\r\n      </div>\r\n\r\n      {/* ── 4. Explanation ──────────────────────────────────────────────────── */}\r\n      {d.explanation && (\r\n        <>\r\n          <Divider />\r\n          <div className=\"px-5 py-6\">\r\n            <SectionLabel>Analysis Report //</SectionLabel>\r\n            <p className=\"font-mono text-[11px] text-muted-foreground/60 leading-relaxed max-w-prose\">\r\n              {d.explanation}\r\n            </p>\r\n          </div>\r\n        </>\r\n      )}\r\n\r\n      {/* ── 5. Extended Telemetry ───────────────────────────────────────────── */}\r\n      {d.hasAdvanced && (\r\n        <>\r\n          <Divider />\r\n          <div className=\"px-5 py-4\">\r\n            <SectionLabel>Extended Telemetry</SectionLabel>\r\n            <div className=\"flex flex-wrap gap-x-6 gap-y-2\">\r\n              {d.nlpScore   !== null && <TinySignal label=\"NLP\"        value={f2(d.nlpScore)} />}\r\n              {d.simScore   !== null && <TinySignal label=\"Similarity\" value={f2(d.simScore)} />}\r\n              {d.styloScore !== null && <TinySignal label=\"Stylometry\" value={f2(d.styloScore)} />}\r\n              {d.urlRisk    !== null && <TinySignal label=\"URL Risk\"   value={f2(d.urlRisk)} />}\r\n              {d.urgency    !== null && <TinySignal label=\"Urgency\"    value={f2(d.urgency)} />}\r\n            </div>\r\n          </div>\r\n        </>\r\n      )}\r\n\r\n    </div>\r\n  )\r\n}\r\n"],"names":[],"mappings":";;;;;AAEA;AAFA;;;AAuDA,SAAS,YAAY,KAAoB,EAAE,QAAiB;IAC1D,IAAI,UAAU;QACZ,MAAM,IAAI,SAAS,WAAW;QAC9B,IAAI,MAAM,SAAS,MAAM,YAAY,MAAM,QAAQ,OAAO;IAC5D;IACA,IAAI,UAAU,MAAM,OAAO;IAC3B,IAAI,QAAQ,KAAK,OAAO;IACxB,IAAI,SAAS,KAAK,OAAO;IACzB,OAAO;AACT;AAEA,SAAS,UAAU,CAAe;IAChC,MAAM,YACJ,OAAO,EAAE,UAAU,KAAK,WAAW,EAAE,UAAU,GAC7C,OAAO,EAAE,YAAY,EAAE,eAAe,WAAW,EAAE,YAAY,CAAE,UAAU,GAC3E,OAAO,EAAE,oBAAoB,KAAK,WAAW,EAAE,oBAAoB,GACnE;IAEJ,MAAM,aACJ,OAAO,EAAE,UAAU,KAAK,WAAW,EAAE,UAAU,GAC7C,OAAO,EAAE,cAAc,KAAK,WAAW,EAAE,cAAc,GACvD;IAEJ,MAAM,YACJ,OAAO,EAAE,UAAU,KAAK,WAAW,EAAE,UAAU,GAC7C,OAAO,EAAE,aAAa,KAAK,WAAW,EAAE,aAAa,GACrD,OAAO,EAAE,YAAY,EAAE,aAAa,YACjC,EAAE,YAAY,CAAE,QAAQ,GAAG,UAAU,UACxC;IAEJ,MAAM,YACJ,EAAE,UAAU,EAAE,SACX,EAAE,cAAc,EAAE,UAClB;IAEL,MAAM,iBACJ,OAAO,EAAE,UAAU,EAAE,eAAe,WAAW,EAAE,UAAU,CAAE,UAAU,GACrE,OAAO,EAAE,cAAc,EAAE,eAAe,WAAW,EAAE,cAAc,CAAE,UAAU,GAC/E;IAEJ,MAAM,QAAkB;WAClB,MAAM,OAAO,CAAC,EAAE,KAAK,IAAK,EAAE,KAAK,GAAgB,EAAE;WACnD,MAAM,OAAO,CAAC,EAAE,YAAY,EAAE,aAAa,EAAE,YAAY,CAAE,SAAS,GAAI,EAAE;KAC/E;IAED,MAAM,cACJ,AAAC,OAAO,EAAE,eAAe,KAAK,YAAY,EAAE,eAAe,CAAC,IAAI,KAC5D,EAAE,eAAe,CAAC,IAAI,KACxB,AAAC,OAAO,EAAE,WAAW,KAAK,YAAY,EAAE,WAAW,CAAC,IAAI,KACtD,EAAE,WAAW,CAAC,IAAI,KACpB,AAAC,OAAO,EAAE,YAAY,EAAE,iBAAiB,YAAY,EAAE,YAAY,CAAE,YAAY,CAAE,IAAI,KACrF,EAAE,YAAY,CAAE,YAAY,CAAE,IAAI,KACpC;IAEJ,MAAM,YAAY,YAAY,WAAW,EAAE,UAAU;IAErD,MAAM,WAAW,OAAO,EAAE,SAAS,KAAK,WAAW,EAAE,SAAS,GAAG;IACjE,MAAM,WAAW,OAAO,EAAE,gBAAgB,KAAK,WAAW,EAAE,gBAAgB,GAAG;IAC/E,MAAM,aAAa,OAAO,EAAE,gBAAgB,KAAK,WAAW,EAAE,gBAAgB,GAAG;IACjF,MAAM,UAAU,OAAO,EAAE,cAAc,KAAK,WAAW,EAAE,cAAc,GAAG;IAC1E,MAAM,UAAU,OAAO,EAAE,aAAa,KAAK,WAAW,EAAE,aAAa,GAAG;IAExE,MAAM,cAAc;QAAC;QAAU;QAAU;QAAY;QAAS;KAAQ,CAAC,IAAI,CAAC,CAAC,IAAM,MAAM;IAEzF,MAAM,QAAQ,OAAO,EAAE,UAAU,KAAK,WAAW,EAAE,UAAU,GAAG;IAEhE,MAAM,cAAc,IAAI,IAAI;QAAC;QAAQ;QAAS;QAAO;KAAkB;IACvE,MAAM,WAAW,CAAC,CAAC,aAAa,CAAC,YAAY,GAAG,CAAC,UAAU,WAAW;IACtE,MAAM,eAAe,CAAC,CAAC,aAAa,CAAC,YAAY,GAAG,CAAC,UAAU,WAAW;IAE1E,OAAO;QACL;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;IACF;AACF;AAEA,gFAAgF;AAEhF,MAAM,MAAM,CAAC,IAAsB,MAAM,OAAO,MAAM,GAAG,CAAC,IAAI,GAAG,EAAE,OAAO,CAAC,GAAG,CAAC,CAAC;AAChF,MAAM,KAAM,CAAC,IAAsB,MAAM,OAAO,MAAM,EAAE,OAAO,CAAC;AAEhE,gFAAgF;AAEhF,MAAM,YAAuC;IAC3C,KAAQ;IACR,QAAQ;IACR,MAAQ;AACV;AAEA,MAAM,cAAyC;IAC7C,KAAQ;IACR,QAAQ;IACR,MAAQ;AACV;AAEA,gFAAgF;AAEhF,SAAS;IACP,qBAAO,8OAAC;QAAI,WAAU;;;;;;AACxB;AAEA,SAAS,aAAa,EAAE,QAAQ,EAA2B;IACzD,qBACE,8OAAC;QAAE,WAAU;kBACV;;;;;;AAGP;AAEA,SAAS,WAAW,EAAE,KAAK,EAAE,KAAK,EAAE,SAAS,KAAK,EAAsD;IACtG,qBACE,8OAAC;;0BACC,8OAAC;gBAAE,WAAU;0BACV;;;;;;0BAEH,8OAAC;gBAAE,WAAW,CAAC,oCAAoC,EAAE,SAAS,gBAAgB,sBAAsB;0BACjG;;;;;;;;;;;;AAIT;AAEA,SAAS,WAAW,EAAE,KAAK,EAAE,KAAK,EAAoC;IACpE,qBACE,8OAAC;QAAI,WAAU;;0BACb,8OAAC;gBAAK,WAAU;0BACb;;;;;;0BAEH,8OAAC;gBAAK,WAAU;0BAAkD;;;;;;;;;;;;AAGxE;AAIO,SAAS,eAAe,EAAE,IAAI,EAA0B;IAC7D,MAAM,UAAU,IAAA,+MAAM,EAAiB;IACvC,MAAM,IAAI,UAAU;IAEpB,wCAAwC;IACxC,IAAA,kNAAS,EAAC;QACR,MAAM,KAAK,QAAQ,OAAO;QAC1B,IAAI,CAAC,IAAI;QACT,GAAG,KAAK,CAAC,OAAO,GAAG;QACnB,GAAG,KAAK,CAAC,SAAS,GAAG;QACrB,MAAM,MAAM,sBAAsB;YAChC,GAAG,KAAK,CAAC,UAAU,GACjB;YACF,GAAG,KAAK,CAAC,OAAO,GAAG;YACnB,GAAG,KAAK,CAAC,SAAS,GAAG;QACvB;QACA,OAAO,IAAM,qBAAqB;IACpC,GAAG,EAAE;IAEL,MAAM,WAAa,EAAE,SAAS,GAAG,SAAS,CAAC,EAAE,SAAS,CAAC,GAAK;IAC5D,MAAM,aAAa,EAAE,SAAS,GAAG,WAAW,CAAC,EAAE,SAAS,CAAC,GAAG;IAE5D,qBACE,8OAAC;QAAI,KAAK;QAAS,WAAW,CAAC,OAAO,EAAE,WAAW,KAAK,CAAC;;0BAGvD,8OAAC;gBAAI,WAAU;;kCACb,8OAAC;wBAAK,WAAU;kCAA4E;;;;;;oBAG3F,EAAE,KAAK,kBACN,8OAAC;wBAAK,WAAU;kCACb,EAAE,KAAK,CAAC,KAAK,CAAC,GAAG,GAAG,WAAW;;;;;;;;;;;;0BAItC,8OAAC;;;;;0BAGD,8OAAC;gBAAI,WAAU;;kCACb,8OAAC;kCAAa;;;;;;kCACd,8OAAC;wBAAI,WAAU;;4BACZ,EAAE,SAAS,KAAK,wBACf,8OAAC;gCAAK,WAAU;;;;;;4BAEjB,EAAE,SAAS,KAAK,0BACf,8OAAC;gCAAK,WAAU;;;;;;0CAElB,8OAAC;gCACC,WAAW,CAAC,0EAA0E,EAAE,UAAU;0CAEjG,EAAE,SAAS,IAAI;;;;;;4BAEjB,EAAE,SAAS,KAAK,sBACf,8OAAC;gCAAK,WAAU;;oCACb,IAAI,EAAE,SAAS;oCAAE;;;;;;;;;;;;;;;;;;;0BAK1B,8OAAC;;;;;0BAGD,8OAAC;gBAAI,WAAU;;kCACb,8OAAC;kCAAa;;;;;;kCACd,8OAAC;wBAAI,WAAU;;0CACb,8OAAC;gCAAW,OAAM;gCAAc,OAAO,IAAI,EAAE,SAAS;;;;;;0CACtD,8OAAC;gCAAW,OAAM;gCAAc,OAAO,IAAI,EAAE,UAAU;;;;;;0CACvD,8OAAC;gCACC,OAAM;gCACN,OAAO,EAAE,SAAS,GAAG,EAAE,SAAS,CAAC,WAAW,KAAK;gCACjD,QAAQ,EAAE,YAAY;;;;;;0CAExB,8OAAC;gCACC,OAAM;gCACN,OAAO,EAAE,SAAS,GAAG,EAAE,SAAS,CAAC,WAAW,KAAK;gCACjD,QAAQ,EAAE,QAAQ;;;;;;;;;;;;;;;;;;0BAIxB,8OAAC;;;;;0BAGD,8OAAC;gBAAI,WAAU;;kCACb,8OAAC;kCACE,EAAE,KAAK,CAAC,MAAM,GAAG,IAAI,CAAC,gBAAgB,EAAE,EAAE,KAAK,CAAC,MAAM,CAAC,CAAC,CAAC,GAAG;;;;;;oBAE9D,EAAE,KAAK,CAAC,MAAM,GAAG,kBAChB,8OAAC;wBAAI,WAAU;kCACZ,EAAE,KAAK,CAAC,GAAG,CAAC,CAAC,MAAM,kBAClB,8OAAC;gCAEC,WAAU;0CAET,KAAK,OAAO,CAAC,MAAM;+BAHf;;;;;;;;;6CAQX,8OAAC;wBAAE,WAAU;kCAAkE;;;;;;;;;;;;YAOlF,EAAE,WAAW,kBACZ;;kCACE,8OAAC;;;;;kCACD,8OAAC;wBAAI,WAAU;;0CACb,8OAAC;0CAAa;;;;;;0CACd,8OAAC;gCAAE,WAAU;0CACV,EAAE,WAAW;;;;;;;;;;;;;;YAOrB,EAAE,WAAW,kBACZ;;kCACE,8OAAC;;;;;kCACD,8OAAC;wBAAI,WAAU;;0CACb,8OAAC;0CAAa;;;;;;0CACd,8OAAC;gCAAI,WAAU;;oCACZ,EAAE,QAAQ,KAAO,sBAAQ,8OAAC;wCAAW,OAAM;wCAAa,OAAO,GAAG,EAAE,QAAQ;;;;;;oCAC5E,EAAE,QAAQ,KAAO,sBAAQ,8OAAC;wCAAW,OAAM;wCAAa,OAAO,GAAG,EAAE,QAAQ;;;;;;oCAC5E,EAAE,UAAU,KAAK,sBAAQ,8OAAC;wCAAW,OAAM;wCAAa,OAAO,GAAG,EAAE,UAAU;;;;;;oCAC9E,EAAE,OAAO,KAAQ,sBAAQ,8OAAC;wCAAW,OAAM;wCAAa,OAAO,GAAG,EAAE,OAAO;;;;;;oCAC3E,EAAE,OAAO,KAAQ,sBAAQ,8OAAC;wCAAW,OAAM;wCAAa,OAAO,GAAG,EAAE,OAAO;;;;;;;;;;;;;;;;;;;;;;;;;;AAQ1F"}},
    {"offset": {"line": 877, "column": 0}, "map": {"version":3,"sources":["file:///C:/HMF/Frontend/app/dashboard/page.tsx"],"sourcesContent":["\"use client\"\r\n\r\nimport { useRef, useEffect, useState, useCallback } from \"react\"\r\nimport Link from \"next/link\"\r\nimport { Input } from \"@/components/ui/input\"\r\nimport { ScrambleTextOnHover } from \"@/components/scramble-text\"\r\nimport { BitmapChevron } from \"@/components/bitmap-chevron\"\r\nimport { AnimatedNoise } from \"@/components/animated-noise\"\r\nimport gsap from \"gsap\"\r\nimport { analyzeSms } from \"@/lib/api/sms\"\r\nimport { analyzeEmail } from \"@/lib/api/email\"\r\nimport { analyzeUrl } from \"@/lib/api/url\"\r\nimport { analyzeVoice } from \"@/lib/api/voice\"\r\nimport { analyzeAttachment } from \"@/lib/api/attachment\"\r\nimport { AnalysisResult, type AnalysisData } from \"@/components/AnalysisResult\"\r\n\r\nconst INPUT_CLS =\r\n  \"bg-transparent border-t-0 border-l-0 border-r-0 border-b border-border/30 rounded-none h-14 px-0 font-mono text-sm focus-visible:ring-0 focus-visible:border-accent transition-all duration-500 placeholder:text-muted-foreground/30\"\r\n\r\nfunction ErrorBlock({ message }: { message: string }) {\r\n  return (\r\n    <div className=\"border border-destructive/25 px-5 py-4 mt-6 font-mono text-[10px] text-destructive/70 leading-relaxed\">\r\n      <span className=\"text-destructive/50 uppercase tracking-[0.3em]\">Error // </span>\r\n      {message}\r\n    </div>\r\n  )\r\n}\r\n\r\nfunction ExecuteButton({\r\n  onClick,\r\n  loading,\r\n  disabled,\r\n}: {\r\n  onClick: () => void\r\n  loading: boolean\r\n  disabled: boolean\r\n}) {\r\n  return (\r\n    <button\r\n      onClick={onClick}\r\n      disabled={disabled || loading}\r\n      className=\"group/btn inline-flex items-center gap-6 border border-foreground/10 px-8 py-4 font-mono text-[10px] uppercase tracking-[0.3em] text-foreground hover:border-accent hover:text-accent transition-all duration-300 disabled:opacity-40 disabled:cursor-not-allowed\"\r\n    >\r\n      <ScrambleTextOnHover\r\n        text={loading ? \"Processing...\" : \"Execute Analysis\"}\r\n        as=\"span\"\r\n        duration={0.5}\r\n      />\r\n      <BitmapChevron className=\"transition-transform duration-500 ease-in-out group-hover/btn:rotate-45\" />\r\n    </button>\r\n  )\r\n}\r\n\r\nexport default function DashboardPage() {\r\n  const containerRef = useRef<HTMLDivElement>(null)\r\n\r\n  // SMS\r\n  const [smsText, setSmsText] = useState(\"\")\r\n  const [smsLoading, setSmsLoading] = useState(false)\r\n  const [smsResult, setSmsResult] = useState<AnalysisData | null>(null)\r\n  const [smsError, setSmsError] = useState<string | null>(null)\r\n\r\n  // Email\r\n  const [emailSender, setEmailSender] = useState(\"\")\r\n  const [emailSubject, setEmailSubject] = useState(\"\")\r\n  const [emailBody, setEmailBody] = useState(\"\")\r\n  const [emailLoading, setEmailLoading] = useState(false)\r\n  const [emailResult, setEmailResult] = useState<AnalysisData | null>(null)\r\n  const [emailError, setEmailError] = useState<string | null>(null)\r\n\r\n  // URL\r\n  const [urlValue, setUrlValue] = useState(\"\")\r\n  const [urlLoading, setUrlLoading] = useState(false)\r\n  const [urlResult, setUrlResult] = useState<AnalysisData | null>(null)\r\n  const [urlError, setUrlError] = useState<string | null>(null)\r\n\r\n  // Voice\r\n  const [voiceFile, setVoiceFile] = useState<File | null>(null)\r\n  const [voiceLoading, setVoiceLoading] = useState(false)\r\n  const [voiceResult, setVoiceResult] = useState<AnalysisData | null>(null)\r\n  const [voiceError, setVoiceError] = useState<string | null>(null)\r\n\r\n  // Attachment\r\n  const [attachFile, setAttachFile] = useState<File | null>(null)\r\n  const [attachLoading, setAttachLoading] = useState(false)\r\n  const [attachResult, setAttachResult] = useState<AnalysisData | null>(null)\r\n  const [attachError, setAttachError] = useState<string | null>(null)\r\n\r\n  useEffect(() => {\r\n    if (!containerRef.current) return\r\n    const ctx = gsap.context(() => {\r\n      gsap.from(\".dashboard-section\", {\r\n        y: 40,\r\n        opacity: 0,\r\n        duration: 0.8,\r\n        stagger: 0.15,\r\n        ease: \"power3.out\",\r\n      })\r\n      gsap.from(\".dashboard-header\", {\r\n        x: -40,\r\n        opacity: 0,\r\n        duration: 1,\r\n        ease: \"power3.out\",\r\n      })\r\n    }, containerRef)\r\n    return () => ctx.revert()\r\n  }, [])\r\n\r\n  const handleSms = useCallback(async () => {\r\n    console.log(\"CLICK [SMS]\")\r\n    if (!smsText.trim()) return\r\n    setSmsLoading(true)\r\n    setSmsResult(null)\r\n    setSmsError(null)\r\n    const payload = { text: smsText, include_llm_explanation: false }\r\n    console.log(\"REQUEST [SMS]:\", payload)\r\n    try {\r\n      const result = await analyzeSms(payload)\r\n      console.log(\"RESPONSE [SMS]:\", result)\r\n      setSmsResult(result)\r\n    } catch (err: unknown) {\r\n      const msg = err instanceof Error ? err.message : \"Analysis failed\"\r\n      console.error(\"ERROR [SMS]:\", err)\r\n      setSmsError(msg)\r\n    } finally {\r\n      setSmsLoading(false)\r\n    }\r\n  }, [smsText])\r\n\r\n  const handleEmail = useCallback(async () => {\r\n    console.log(\"CLICK [Email]\")\r\n    if (!emailSender.trim() || !emailBody.trim()) return\r\n    setEmailLoading(true)\r\n    setEmailResult(null)\r\n    setEmailError(null)\r\n    const payload = {\r\n      sender: emailSender,\r\n      subject: emailSubject,\r\n      body: emailBody,\r\n      with_llm_explanation: false,\r\n    }\r\n    console.log(\"REQUEST [Email]:\", payload)\r\n    try {\r\n      const result = await analyzeEmail(payload)\r\n      console.log(\"RESPONSE [Email]:\", result)\r\n      setEmailResult(result)\r\n    } catch (err: unknown) {\r\n      const msg = err instanceof Error ? err.message : \"Analysis failed\"\r\n      console.error(\"ERROR [Email]:\", err)\r\n      setEmailError(msg)\r\n    } finally {\r\n      setEmailLoading(false)\r\n    }\r\n  }, [emailSender, emailSubject, emailBody])\r\n\r\n  const handleUrl = useCallback(async () => {\r\n    console.log(\"CLICK [URL]\")\r\n    if (!urlValue.trim()) return\r\n    setUrlLoading(true)\r\n    setUrlResult(null)\r\n    setUrlError(null)\r\n    const payload = { url: urlValue, with_llm_explanation: false }\r\n    console.log(\"REQUEST [URL]:\", payload)\r\n    try {\r\n      const result = await analyzeUrl(payload)\r\n      console.log(\"RESPONSE [URL]:\", result)\r\n      setUrlResult(result)\r\n    } catch (err: unknown) {\r\n      const msg = err instanceof Error ? err.message : \"Analysis failed\"\r\n      console.error(\"ERROR [URL]:\", err)\r\n      setUrlError(msg)\r\n    } finally {\r\n      setUrlLoading(false)\r\n    }\r\n  }, [urlValue])\r\n\r\n  const handleVoice = useCallback(async () => {\r\n    console.log(\"CLICK [Voice]\")\r\n    if (!voiceFile) return\r\n    setVoiceLoading(true)\r\n    setVoiceResult(null)\r\n    setVoiceError(null)\r\n    console.log(\"REQUEST [Voice]:\", { file: voiceFile.name, size: voiceFile.size })\r\n    try {\r\n      const result = await analyzeVoice(voiceFile)\r\n      console.log(\"RESPONSE [Voice]:\", result)\r\n      setVoiceResult(result)\r\n    } catch (err: unknown) {\r\n      const msg = err instanceof Error ? err.message : \"Analysis failed\"\r\n      console.error(\"ERROR [Voice]:\", err)\r\n      setVoiceError(msg)\r\n    } finally {\r\n      setVoiceLoading(false)\r\n    }\r\n  }, [voiceFile])\r\n\r\n  const handleAttachment = useCallback(async () => {\r\n    console.log(\"CLICK [Attachment]\")\r\n    if (!attachFile) return\r\n    setAttachLoading(true)\r\n    setAttachResult(null)\r\n    setAttachError(null)\r\n    console.log(\"REQUEST [Attachment]:\", { file: attachFile.name, size: attachFile.size })\r\n    try {\r\n      const result = await analyzeAttachment(attachFile, false)\r\n      console.log(\"RESPONSE [Attachment]:\", result)\r\n      setAttachResult(result)\r\n    } catch (err: unknown) {\r\n      const msg = err instanceof Error ? err.message : \"Analysis failed\"\r\n      console.error(\"ERROR [Attachment]:\", err)\r\n      setAttachError(msg)\r\n    } finally {\r\n      setAttachLoading(false)\r\n    }\r\n  }, [attachFile])\r\n\r\n  return (\r\n    <main\r\n      ref={containerRef}\r\n      className=\"relative min-h-screen bg-background text-foreground selection:bg-accent selection:text-background\"\r\n    >\r\n      <AnimatedNoise opacity={0.02} />\r\n      <div className=\"grid-bg fixed inset-0 opacity-20 pointer-events-none\" aria-hidden=\"true\" />\r\n\r\n      {/* Top Nav */}\r\n      <nav className=\"relative z-50 flex items-center justify-between px-6 py-6 md:px-12 border-b border-border/10 backdrop-blur-md bg-background/40\">\r\n        <div className=\"flex items-center gap-4\">\r\n          <span className=\"font-mono text-[10px] uppercase tracking-[0.4em] text-accent font-bold\">Rapid3</span>\r\n          <span className=\"h-px w-8 bg-border/40\" />\r\n          <span className=\"font-mono text-[10px] uppercase tracking-[0.4em] text-muted-foreground\">\r\n            Operative Interface\r\n          </span>\r\n        </div>\r\n        <Link\r\n          href=\"/\"\r\n          className=\"font-mono text-[10px] uppercase tracking-[0.3em] text-muted-foreground hover:text-accent transition-colors\"\r\n        >\r\n          Logout // Disconnect\r\n        </Link>\r\n      </nav>\r\n\r\n      <div className=\"relative z-10 max-w-7xl mx-auto px-6 py-16 md:px-12 md:py-24\">\r\n        {/* Header */}\r\n        <header className=\"dashboard-header mb-24 max-w-2xl\">\r\n          <span className=\"font-mono text-[10px] uppercase tracking-[0.5em] text-accent block mb-4\">\r\n            Command Center\r\n          </span>\r\n          <h1 className=\"font-[var(--font-bebas)] text-7xl md:text-9xl tracking-tighter leading-[0.8] mb-8\">\r\n            DASHBOARD\r\n          </h1>\r\n          <p className=\"font-mono text-sm text-muted-foreground leading-relaxed max-w-md\">\r\n            Active defensive layers are online. Deploy localized intelligence across multiple threat vectors.\r\n          </p>\r\n        </header>\r\n\r\n        {/* Grid */}\r\n        <div className=\"grid grid-cols-1 lg:grid-cols-2 gap-x-24 gap-y-32\">\r\n\r\n          {/* 01 — SMS */}\r\n          <section className=\"dashboard-section group relative\">\r\n            <div className=\"flex items-baseline gap-4 mb-8\">\r\n              <span className=\"font-mono text-[10px] text-accent border border-accent/20 px-2 py-1\">01</span>\r\n              <h2 className=\"font-[var(--font-bebas)] text-4xl md:text-5xl tracking-tight group-hover:text-accent transition-colors duration-300\">\r\n                SMS Analysis\r\n              </h2>\r\n            </div>\r\n            <p className=\"font-mono text-xs text-muted-foreground mb-10 leading-relaxed max-w-sm\">\r\n              Detect phishing patterns and malicious intent in mobile communications.\r\n            </p>\r\n            <div className=\"space-y-6\">\r\n              <div className=\"relative\">\r\n                <Input\r\n                  value={smsText}\r\n                  onChange={(e) => setSmsText(e.target.value)}\r\n                  placeholder=\"Enter SMS content for threat vectoring...\"\r\n                  className={INPUT_CLS}\r\n                />\r\n                <div className=\"absolute bottom-0 left-0 h-[2px] w-0 bg-accent transition-all duration-700 group-focus-within:w-full\" />\r\n              </div>\r\n              <div className=\"flex justify-end\">\r\n                <ExecuteButton\r\n                  onClick={handleSms}\r\n                  loading={smsLoading}\r\n                  disabled={!smsText.trim()}\r\n                />\r\n              </div>\r\n              {smsError && <ErrorBlock message={smsError} />}\r\n              {smsResult && <AnalysisResult data={smsResult} />}\r\n            </div>\r\n            <div className=\"absolute -inset-8 -z-10 bg-accent/[0.02] opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-lg pointer-events-none\" />\r\n          </section>\r\n\r\n          {/* 02 — Email */}\r\n          <section className=\"dashboard-section group relative\">\r\n            <div className=\"flex items-baseline gap-4 mb-8\">\r\n              <span className=\"font-mono text-[10px] text-accent border border-accent/20 px-2 py-1\">02</span>\r\n              <h2 className=\"font-[var(--font-bebas)] text-4xl md:text-5xl tracking-tight group-hover:text-accent transition-colors duration-300\">\r\n                Email Analysis\r\n              </h2>\r\n            </div>\r\n            <p className=\"font-mono text-xs text-muted-foreground mb-10 leading-relaxed max-w-sm\">\r\n              Deep packet inspection of SMTP artifacts and social engineering markers.\r\n            </p>\r\n            <div className=\"space-y-6\">\r\n              <div className=\"relative\">\r\n                <Input\r\n                  value={emailSender}\r\n                  onChange={(e) => setEmailSender(e.target.value)}\r\n                  placeholder=\"Sender address...\"\r\n                  className={INPUT_CLS}\r\n                />\r\n                <div className=\"absolute bottom-0 left-0 h-[2px] w-0 bg-accent transition-all duration-700 group-focus-within:w-full\" />\r\n              </div>\r\n              <div className=\"relative\">\r\n                <Input\r\n                  value={emailSubject}\r\n                  onChange={(e) => setEmailSubject(e.target.value)}\r\n                  placeholder=\"Subject line...\"\r\n                  className={INPUT_CLS}\r\n                />\r\n              </div>\r\n              <div className=\"relative\">\r\n                <Input\r\n                  value={emailBody}\r\n                  onChange={(e) => setEmailBody(e.target.value)}\r\n                  placeholder=\"Paste email body or headers...\"\r\n                  className={INPUT_CLS}\r\n                />\r\n              </div>\r\n              <div className=\"flex justify-end\">\r\n                <ExecuteButton\r\n                  onClick={handleEmail}\r\n                  loading={emailLoading}\r\n                  disabled={!emailSender.trim() || !emailBody.trim()}\r\n                />\r\n              </div>\r\n              {emailError && <ErrorBlock message={emailError} />}\r\n              {emailResult && <AnalysisResult data={emailResult} />}\r\n            </div>\r\n            <div className=\"absolute -inset-8 -z-10 bg-accent/[0.02] opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-lg pointer-events-none\" />\r\n          </section>\r\n\r\n          {/* 03 — URL */}\r\n          <section className=\"dashboard-section group relative\">\r\n            <div className=\"flex items-baseline gap-4 mb-8\">\r\n              <span className=\"font-mono text-[10px] text-accent border border-accent/20 px-2 py-1\">03</span>\r\n              <h2 className=\"font-[var(--font-bebas)] text-4xl md:text-5xl tracking-tight group-hover:text-accent transition-colors duration-300\">\r\n                URL Analysis\r\n              </h2>\r\n            </div>\r\n            <p className=\"font-mono text-xs text-muted-foreground mb-10 leading-relaxed max-w-sm\">\r\n              Real-time domain reputation and recursive redirect tracing.\r\n            </p>\r\n            <div className=\"space-y-6\">\r\n              <div className=\"relative\">\r\n                <Input\r\n                  value={urlValue}\r\n                  onChange={(e) => setUrlValue(e.target.value)}\r\n                  placeholder=\"https://\"\r\n                  className={INPUT_CLS}\r\n                />\r\n                <div className=\"absolute bottom-0 left-0 h-[2px] w-0 bg-accent transition-all duration-700 group-focus-within:w-full\" />\r\n              </div>\r\n              <div className=\"flex justify-end\">\r\n                <ExecuteButton\r\n                  onClick={handleUrl}\r\n                  loading={urlLoading}\r\n                  disabled={!urlValue.trim()}\r\n                />\r\n              </div>\r\n              {urlError && <ErrorBlock message={urlError} />}\r\n              {urlResult && <AnalysisResult data={urlResult} />}\r\n            </div>\r\n            <div className=\"absolute -inset-8 -z-10 bg-accent/[0.02] opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-lg pointer-events-none\" />\r\n          </section>\r\n\r\n          {/* 04 — Voice */}\r\n          <section className=\"dashboard-section group relative\">\r\n            <div className=\"flex items-baseline gap-4 mb-8\">\r\n              <span className=\"font-mono text-[10px] text-accent border border-accent/20 px-2 py-1\">04</span>\r\n              <h2 className=\"font-[var(--font-bebas)] text-4xl md:text-5xl tracking-tight group-hover:text-accent transition-colors duration-300\">\r\n                Voice Analysis\r\n              </h2>\r\n            </div>\r\n            <p className=\"font-mono text-xs text-muted-foreground mb-10 leading-relaxed max-w-sm\">\r\n              ResNetBiLSTM analysis for synthetic voice and deepfake detection.\r\n            </p>\r\n            <div className=\"space-y-6\">\r\n              <div className=\"relative border-b border-border/30\">\r\n                <label className=\"flex items-center h-14 px-0 font-mono text-sm cursor-pointer\">\r\n                  <input\r\n                    type=\"file\"\r\n                    accept=\"audio/*\"\r\n                    className=\"sr-only\"\r\n                    onChange={(e) => {\r\n                      const f = e.target.files?.[0] ?? null\r\n                      setVoiceFile(f)\r\n                      setVoiceResult(null)\r\n                      setVoiceError(null)\r\n                    }}\r\n                  />\r\n                  {voiceFile ? (\r\n                    <span className=\"text-accent/70\">{voiceFile.name}</span>\r\n                  ) : (\r\n                    <span className=\"text-muted-foreground/30\">Upload audio sample...</span>\r\n                  )}\r\n                </label>\r\n                <div className=\"absolute bottom-0 left-0 h-[2px] w-0 bg-accent transition-all duration-700 group-focus-within:w-full\" />\r\n              </div>\r\n              <div className=\"flex justify-end\">\r\n                <ExecuteButton\r\n                  onClick={handleVoice}\r\n                  loading={voiceLoading}\r\n                  disabled={!voiceFile}\r\n                />\r\n              </div>\r\n              {voiceError && <ErrorBlock message={voiceError} />}\r\n              {voiceResult && <AnalysisResult data={voiceResult} />}\r\n            </div>\r\n            <div className=\"absolute -inset-8 -z-10 bg-accent/[0.02] opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-lg pointer-events-none\" />\r\n          </section>\r\n\r\n          {/* 05 — Attachment */}\r\n          <section className=\"dashboard-section group relative\">\r\n            <div className=\"flex items-baseline gap-4 mb-8\">\r\n              <span className=\"font-mono text-[10px] text-accent border border-accent/20 px-2 py-1\">05</span>\r\n              <h2 className=\"font-[var(--font-bebas)] text-4xl md:text-5xl tracking-tight group-hover:text-accent transition-colors duration-300\">\r\n                File Analysis\r\n              </h2>\r\n            </div>\r\n            <p className=\"font-mono text-xs text-muted-foreground mb-10 leading-relaxed max-w-sm\">\r\n              YARA-based signature matching and behavioral sandbox analysis.\r\n            </p>\r\n            <div className=\"space-y-6\">\r\n              <div className=\"relative border-b border-border/30\">\r\n                <label className=\"flex items-center h-14 px-0 font-mono text-sm cursor-pointer\">\r\n                  <input\r\n                    type=\"file\"\r\n                    className=\"sr-only\"\r\n                    onChange={(e) => {\r\n                      const f = e.target.files?.[0] ?? null\r\n                      setAttachFile(f)\r\n                      setAttachResult(null)\r\n                      setAttachError(null)\r\n                    }}\r\n                  />\r\n                  {attachFile ? (\r\n                    <span className=\"text-accent/70\">{attachFile.name}</span>\r\n                  ) : (\r\n                    <span className=\"text-muted-foreground/30\">Select artifact for scanning...</span>\r\n                  )}\r\n                </label>\r\n                <div className=\"absolute bottom-0 left-0 h-[2px] w-0 bg-accent transition-all duration-700 group-focus-within:w-full\" />\r\n              </div>\r\n              <div className=\"flex justify-end\">\r\n                <ExecuteButton\r\n                  onClick={handleAttachment}\r\n                  loading={attachLoading}\r\n                  disabled={!attachFile}\r\n                />\r\n              </div>\r\n              {attachError && <ErrorBlock message={attachError} />}\r\n              {attachResult && <AnalysisResult data={attachResult} />}\r\n            </div>\r\n            <div className=\"absolute -inset-8 -z-10 bg-accent/[0.02] opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-lg pointer-events-none\" />\r\n          </section>\r\n\r\n        </div>\r\n\r\n        {/* Footer */}\r\n        <footer className=\"mt-48 pt-12 border-t border-border/10 flex flex-col md:flex-row justify-between gap-8 font-mono text-[9px] uppercase tracking-[0.4em] text-muted-foreground/40\">\r\n          <div className=\"flex gap-8\">\r\n            <span>Uptime: 99.9997%</span>\r\n            <span>Latency: 12ms</span>\r\n            <span>Nodes: Active [32]</span>\r\n          </div>\r\n          <div className=\"flex gap-8\">\r\n            <span>SECURE_SESSION: RF-9021</span>\r\n            <span>ENCRYPTION: AES-256-GCM</span>\r\n          </div>\r\n        </footer>\r\n      </div>\r\n\r\n      {/* Floating Tag */}\r\n      <div className=\"fixed bottom-12 right-12 hidden xl:block z-50\">\r\n        <div className=\"border border-border/30 px-6 py-3 font-mono text-[10px] uppercase tracking-[0.3em] text-muted-foreground backdrop-blur-md bg-background/20\">\r\n          INTERFACE_V01 // DEFENSIVE_STATE\r\n        </div>\r\n      </div>\r\n    </main>\r\n  )\r\n}\r\n"],"names":[],"mappings":";;;;;AAEA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AAdA;;;;;;;;;;;;;;;AAgBA,MAAM,YACJ;AAEF,SAAS,WAAW,EAAE,OAAO,EAAuB;IAClD,qBACE,8OAAC;QAAI,WAAU;;0BACb,8OAAC;gBAAK,WAAU;0BAAiD;;;;;;YAChE;;;;;;;AAGP;AAEA,SAAS,cAAc,EACrB,OAAO,EACP,OAAO,EACP,QAAQ,EAKT;IACC,qBACE,8OAAC;QACC,SAAS;QACT,UAAU,YAAY;QACtB,WAAU;;0BAEV,8OAAC,sJAAmB;gBAClB,MAAM,UAAU,kBAAkB;gBAClC,IAAG;gBACH,UAAU;;;;;;0BAEZ,8OAAC,iJAAa;gBAAC,WAAU;;;;;;;;;;;;AAG/B;AAEe,SAAS;IACtB,MAAM,eAAe,IAAA,+MAAM,EAAiB;IAE5C,MAAM;IACN,MAAM,CAAC,SAAS,WAAW,GAAG,IAAA,iNAAQ,EAAC;IACvC,MAAM,CAAC,YAAY,cAAc,GAAG,IAAA,iNAAQ,EAAC;IAC7C,MAAM,CAAC,WAAW,aAAa,GAAG,IAAA,iNAAQ,EAAsB;IAChE,MAAM,CAAC,UAAU,YAAY,GAAG,IAAA,iNAAQ,EAAgB;IAExD,QAAQ;IACR,MAAM,CAAC,aAAa,eAAe,GAAG,IAAA,iNAAQ,EAAC;IAC/C,MAAM,CAAC,cAAc,gBAAgB,GAAG,IAAA,iNAAQ,EAAC;IACjD,MAAM,CAAC,WAAW,aAAa,GAAG,IAAA,iNAAQ,EAAC;IAC3C,MAAM,CAAC,cAAc,gBAAgB,GAAG,IAAA,iNAAQ,EAAC;IACjD,MAAM,CAAC,aAAa,eAAe,GAAG,IAAA,iNAAQ,EAAsB;IACpE,MAAM,CAAC,YAAY,cAAc,GAAG,IAAA,iNAAQ,EAAgB;IAE5D,MAAM;IACN,MAAM,CAAC,UAAU,YAAY,GAAG,IAAA,iNAAQ,EAAC;IACzC,MAAM,CAAC,YAAY,cAAc,GAAG,IAAA,iNAAQ,EAAC;IAC7C,MAAM,CAAC,WAAW,aAAa,GAAG,IAAA,iNAAQ,EAAsB;IAChE,MAAM,CAAC,UAAU,YAAY,GAAG,IAAA,iNAAQ,EAAgB;IAExD,QAAQ;IACR,MAAM,CAAC,WAAW,aAAa,GAAG,IAAA,iNAAQ,EAAc;IACxD,MAAM,CAAC,cAAc,gBAAgB,GAAG,IAAA,iNAAQ,EAAC;IACjD,MAAM,CAAC,aAAa,eAAe,GAAG,IAAA,iNAAQ,EAAsB;IACpE,MAAM,CAAC,YAAY,cAAc,GAAG,IAAA,