    {"offset": {"line": 19, "column": 0}, "map": {"version":3,"sources":["file:///Users/aarav/Desktop/Neural-Nexus/Frontend/components/ui/input.tsx"],"sourcesContent":["import * as React from 'react'\n\nimport { cn } from '@/lib/utils'\n\nfunction Input({ className, type, ...props }: React.ComponentProps<'input'>) {\n  return (\n    <input\n      type={type}\n      data-slot=\"input\"\n      className={cn(\n        'file:text-foreground placeholder:text-muted-foreground selection:bg-primary selection:text-primary-foreground dark:bg-input/30 border-input h-9 w-full min-w-0 rounded-md border bg-transparent px-3 py-1 text-base shadow-xs transition-[color,box-shadow] outline-none file:inline-flex file:h-7 file:border-0 file:bg-transparent file:text-sm file:font-medium disabled:pointer-events-none disabled:cursor-not-allowed disabled:opacity-50 md:text-sm',\n        'focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px]',\n        'aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive',\n        className,\n      )}\n      {...props}\n    />\n  )\n}\n\nexport { Input }\n"],"names":[],"mappings":";;;;;AAEA;;;AAEA,SAAS,MAAM,EAAE,SAAS,EAAE,IAAI,EAAE,GAAG,OAAsC;IACzE,qBACE,8OAAC;QACC,MAAM;QACN,aAAU;QACV,WAAW,IAAA,kHAAE,EACX,8bACA,iFACA,0GACA;QAED,GAAG,KAAK;;;;;;AAGf"}},
    {"offset": {"line": 44, "column": 0}, "map": {"version":3,"sources":["file:///Users/aarav/Desktop/Neural-Nexus/Frontend/components/scramble-text.tsx"],"sourcesContent":["\"use client\"\n\nimport { useEffect, useState, useRef, useCallback } from \"react\"\nimport gsap from \"gsap\"\n\ninterface ScrambleTextProps {\n  text: string\n  className?: string\n  /** Delay in milliseconds before animation starts */\n  delayMs?: number\n  /** Duration of the scramble animation in seconds */\n  duration?: number\n}\n\ninterface ScrambleTextOnHoverProps {\n  text: string\n  className?: string\n  /** Duration of the scramble animation in seconds */\n  duration?: number\n  /** Element type to render */\n  as?: \"span\" | \"button\" | \"div\"\n  /** onClick handler for buttons */\n  onClick?: () => void\n}\n\nconst GLYPHS = \"!@#$%^&*()_+-=<>?/\\\\[]{}Xx\"\n\n/**\n * Run the scramble animation on text\n */\nfunction runScrambleAnimation(\n  text: string,\n  duration: number,\n  setDisplayText: (text: string) => void,\n  onComplete?: () => void,\n): gsap.core.Tween {\n  const lockedIndices = new Set<number>()\n  const finalChars = text.split(\"\")\n  const totalChars = finalChars.length\n  const scrambleObj = { progress: 0 }\n\n  return gsap.to(scrambleObj, {\n    progress: 1,\n    duration,\n    ease: \"power2.out\",\n    onUpdate: () => {\n      const numLocked = Math.floor(scrambleObj.progress * totalChars)\n\n      for (let i = 0; i < numLocked; i++) {\n        lockedIndices.add(i)\n      }\n\n      const newDisplay = finalChars\n        .map((char, i) => {\n          if (lockedIndices.has(i)) return char\n          return GLYPHS[Math.floor(Math.random() * GLYPHS.length)]\n        })\n        .join(\"\")\n\n      setDisplayText(newDisplay)\n    },\n    onComplete: () => {\n      setDisplayText(text)\n      onComplete?.()\n    },\n  })\n}\n\n/**\n * Scramble text animation component - animates on mount.\n */\nexport function ScrambleText({ text, className, delayMs = 0, duration = 0.9 }: ScrambleTextProps) {\n  // Initialize with text to avoid flash of empty content\n  const [displayText, setDisplayText] = useState(text)\n  const [hasAnimated, setHasAnimated] = useState(false)\n  const containerRef = useRef<HTMLSpanElement>(null)\n  const animationRef = useRef<gsap.core.Tween | null>(null)\n  const timeoutRef = useRef<NodeJS.Timeout | null>(null)\n\n  // Run animation only once on initial mount\n  useEffect(() => {\n    if (hasAnimated || !text) return\n\n    // Start with scrambled text\n    const scrambledStart = text\n      .split(\"\")\n      .map(() => GLYPHS[Math.floor(Math.random() * GLYPHS.length)])\n      .join(\"\")\n    setDisplayText(scrambledStart)\n\n    timeoutRef.current = setTimeout(() => {\n      animationRef.current = runScrambleAnimation(text, duration, setDisplayText, () => {\n        setHasAnimated(true)\n      })\n    }, delayMs)\n\n    return () => {\n      if (timeoutRef.current) clearTimeout(timeoutRef.current)\n      if (animationRef.current) animationRef.current.kill()\n    }\n  }, []) // Empty deps - only run on mount\n\n  // Handle text prop changes after initial animation\n  useEffect(() => {\n    if (hasAnimated && displayText !== text) {\n      setDisplayText(text)\n    }\n  }, [text, hasAnimated, displayText])\n\n  return (\n    <span ref={containerRef} className={className}>\n      {displayText || text}\n    </span>\n  )\n}\n\n/**\n * Scramble text animation component - animates on hover.\n */\nexport function ScrambleTextOnHover({\n  text,\n  className,\n  duration = 0.4,\n  as: Component = \"span\",\n  onClick,\n}: ScrambleTextOnHoverProps) {\n  const [displayText, setDisplayText] = useState(text)\n  const isAnimating = useRef(false)\n  const tweenRef = useRef<gsap.core.Tween | null>(null)\n\n  const handleMouseEnter = useCallback(() => {\n    if (isAnimating.current) return\n    isAnimating.current = true\n\n    // Kill any existing animation\n    if (tweenRef.current) {\n      tweenRef.current.kill()\n    }\n\n    // Start with scrambled\n    const scrambledStart = text\n      .split(\"\")\n      .map(() => GLYPHS[Math.floor(Math.random() * GLYPHS.length)])\n      .join(\"\")\n    setDisplayText(scrambledStart)\n\n    tweenRef.current = runScrambleAnimation(text, duration, setDisplayText, () => {\n      isAnimating.current = false\n    })\n  }, [text, duration])\n\n  // Update display text if text prop changes\n  useEffect(() => {\n    if (!isAnimating.current) {\n      setDisplayText(text)\n    }\n  }, [text])\n\n  return (\n    <Component className={className} onMouseEnter={handleMouseEnter} onClick={onClick}>\n      {displayText}\n    </Component>\n  )\n}\n"],"names":[],"mappings":";;;;;;;AAEA;AACA;AAHA;;;;AAyBA,MAAM,SAAS;AAEf;;CAEC,GACD,SAAS,qBACP,IAAY,EACZ,QAAgB,EAChB,cAAsC,EACtC,UAAuB;IAEvB,MAAM,gBAAgB,IAAI;IAC1B,MAAM,aAAa,KAAK,KAAK,CAAC;IAC9B,MAAM,aAAa,WAAW,MAAM;IACpC,MAAM,cAAc;QAAE,UAAU;IAAE;IAElC,OAAO,wJAAI,CAAC,EAAE,CAAC,aAAa;QAC1B,UAAU;QACV;QACA,MAAM;QACN,UAAU;YACR,MAAM,YAAY,KAAK,KAAK,CAAC,YAAY,QAAQ,GAAG;YAEpD,IAAK,IAAI,IAAI,GAAG,IAAI,WAAW,IAAK;gBAClC,cAAc,GAAG,CAAC;YACpB;YAEA,MAAM,aAAa,WAChB,GAAG,CAAC,CAAC,MAAM;gBACV,IAAI,cAAc,GAAG,CAAC,IAAI,OAAO;gBACjC,OAAO,MAAM,CAAC,KAAK,KAAK,CAAC,KAAK,MAAM,KAAK,OAAO,MAAM,EAAE;YAC1D,GACC,IAAI,CAAC;YAER,eAAe;QACjB;QACA,YAAY;YACV,eAAe;YACf;QACF;IACF;AACF;AAKO,SAAS,aAAa,EAAE,IAAI,EAAE,SAAS,EAAE,UAAU,CAAC,EAAE,WAAW,GAAG,EAAqB;IAC9F,uDAAuD;IACvD,MAAM,CAAC,aAAa,eAAe,GAAG,IAAA,iNAAQ,EAAC;IAC/C,MAAM,CAAC,aAAa,eAAe,GAAG,IAAA,iNAAQ,EAAC;IAC/C,MAAM,eAAe,IAAA,+MAAM,EAAkB;IAC7C,MAAM,eAAe,IAAA,+MAAM,EAAyB;IACpD,MAAM,aAAa,IAAA,+MAAM,EAAwB;IAEjD,2CAA2C;IAC3C,IAAA,kNAAS,EAAC;QACR,IAAI,eAAe,CAAC,MAAM;QAE1B,4BAA4B;QAC5B,MAAM,iBAAiB,KACpB,KAAK,CAAC,IACN,GAAG,CAAC,IAAM,MAAM,CAAC,KAAK,KAAK,CAAC,KAAK,MAAM,KAAK,OAAO,MAAM,EAAE,EAC3D,IAAI,CAAC;QACR,eAAe;QAEf,WAAW,OAAO,GAAG,WAAW;YAC9B,aAAa,OAAO,GAAG,qBAAqB,MAAM,UAAU,gBAAgB;gBAC1E,eAAe;YACjB;QACF,GAAG;QAEH,OAAO;YACL,IAAI,WAAW,OAAO,EAAE,aAAa,WAAW,OAAO;YACvD,IAAI,aAAa,OAAO,EAAE,aAAa,OAAO,CAAC,IAAI;QACrD;IACF,GAAG,EAAE,GAAE,iCAAiC;IAExC,mDAAmD;IACnD,IAAA,kNAAS,EAAC;QACR,IAAI,eAAe,gBAAgB,MAAM;YACvC,eAAe;QACjB;IACF,GAAG;QAAC;QAAM;QAAa;KAAY;IAEnC,qBACE,8OAAC;QAAK,KAAK;QAAc,WAAW;kBACjC,eAAe;;;;;;AAGtB;AAKO,SAAS,oBAAoB,EAClC,IAAI,EACJ,SAAS,EACT,WAAW,GAAG,EACd,IAAI,YAAY,MAAM,EACtB,OAAO,EACkB;IACzB,MAAM,CAAC,aAAa,eAAe,GAAG,IAAA,iNAAQ,EAAC;IAC/C,MAAM,cAAc,IAAA,+MAAM,EAAC;IAC3B,MAAM,WAAW,IAAA,+MAAM,EAAyB;IAEhD,MAAM,mBAAmB,IAAA,oNAAW,EAAC;QACnC,IAAI,YAAY,OAAO,EAAE;QACzB,YAAY,OAAO,GAAG;QAEtB,8BAA8B;QAC9B,IAAI,SAAS,OAAO,EAAE;YACpB,SAAS,OAAO,CAAC,IAAI;QACvB;QAEA,uBAAuB;QACvB,MAAM,iBAAiB,KACpB,KAAK,CAAC,IACN,GAAG,CAAC,IAAM,MAAM,CAAC,KAAK,KAAK,CAAC,KAAK,MAAM,KAAK,OAAO,MAAM,EAAE,EAC3D,IAAI,CAAC;QACR,eAAe;QAEf,SAAS,OAAO,GAAG,qBAAqB,MAAM,UAAU,gBAAgB;YACtE,YAAY,OAAO,GAAG;QACxB;IACF,GAAG;QAAC;QAAM;KAAS;IAEnB,2CAA2C;IAC3C,IAAA,kNAAS,EAAC;QACR,IAAI,CAAC,YAAY,OAAO,EAAE;YACxB,eAAe;QACjB;IACF,GAAG;QAAC;KAAK;IAET,qBACE,8OAAC;QAAU,WAAW;QAAW,cAAc;QAAkB,SAAS;kBACvE;;;;;;AAGP"}},
    {"offset": {"line": 175, "column": 0}, "map": {"version":3,"sources":["file:///Users/aarav/Desktop/Neural-Nexus/Frontend/components/bitmap-chevron.tsx"],"sourcesContent":["export function BitmapChevron({ className }: { className?: string }) {\n  return (\n    <svg\n      width=\"18\"\n      height=\"18\"\n      viewBox=\"0 0 27 27\"\n      fill=\"none\"\n      xmlns=\"http://www.w3.org/2000/svg\"\n      className={className}\n    >\n      <path\n        d=\"M3.85715 3.85715H19.2857L23.0553 7.64066L17.5163 13.1595L22.8462 17.5055V23.1429H17.5055V13.1703L7.65696 22.9832L3.8874 19.2L13.9259 9.19781H3.85715V3.85715Z\"\n        fill=\"currentColor\"\n      />\n    </svg>\n  )\n}\n"],"names":[],"mappings":";;;;;;AAAO,SAAS,cAAc,EAAE,SAAS,EAA0B;IACjE,qBACE,8OAAC;QACC,OAAM;QACN,QAAO;QACP,SAAQ;QACR,MAAK;QACL,OAAM;QACN,WAAW;kBAEX,cAAA,8OAAC;YACC,GAAE;YACF,MAAK;;;;;;;;;;;AAIb"}},
    {"offset": {"line": 207, "column": 0}, "map": {"version":3,"sources":["file:///Users/aarav/Desktop/Neural-Nexus/Frontend/components/animated-noise.tsx"],"sourcesContent":["\"use client\"\n\nimport { useEffect, useRef } from \"react\"\n\ninterface AnimatedNoiseProps {\n  opacity?: number\n  className?: string\n}\n\nexport function AnimatedNoise({ opacity = 0.05, className }: AnimatedNoiseProps) {\n  const canvasRef = useRef<HTMLCanvasElement>(null)\n\n  useEffect(() => {\n    const canvas = canvasRef.current\n    if (!canvas) return\n\n    const ctx = canvas.getContext(\"2d\")\n    if (!ctx) return\n\n    let animationId: number\n    let frame = 0\n\n    const resize = () => {\n      canvas.width = canvas.offsetWidth / 2\n      canvas.height = canvas.offsetHeight / 2\n    }\n\n    const generateNoise = () => {\n      const imageData = ctx.createImageData(canvas.width, canvas.height)\n      const data = imageData.data\n\n      for (let i = 0; i < data.length; i += 4) {\n        const value = Math.random() * 255\n        data[i] = value // R\n        data[i + 1] = value // G\n        data[i + 2] = value // B\n        data[i + 3] = 255 // A\n      }\n\n      ctx.putImageData(imageData, 0, 0)\n    }\n\n    const animate = () => {\n      frame++\n      // Update noise every 2 frames for performance while still looking animated\n      if (frame % 2 === 0) {\n        generateNoise()\n      }\n      animationId = requestAnimationFrame(animate)\n    }\n\n    resize()\n    window.addEventListener(\"resize\", resize)\n    animate()\n\n    return () => {\n      window.removeEventListener(\"resize\", resize)\n      cancelAnimationFrame(animationId)\n    }\n  }, [])\n\n  return (\n    <canvas\n      ref={canvasRef}\n      className={className}\n      style={{\n        position: \"absolute\",\n        inset: 0,\n        width: \"100%\",\n        height: \"100%\",\n        pointerEvents: \"none\",\n        opacity,\n        mixBlendMode: \"overlay\",\n      }}\n    />\n  )\n}\n"],"names":[],"mappings":";;;;;AAEA;AAFA;;;AASO,SAAS,cAAc,EAAE,UAAU,IAAI,EAAE,SAAS,EAAsB;IAC7E,MAAM,YAAY,IAAA,+MAAM,EAAoB;IAE5C,IAAA,kNAAS,EAAC;QACR,MAAM,SAAS,UAAU,OAAO;QAChC,IAAI,CAAC,QAAQ;QAEb,MAAM,MAAM,OAAO,UAAU,CAAC;QAC9B,IAAI,CAAC,KAAK;QAEV,IAAI;QACJ,IAAI,QAAQ;QAEZ,MAAM,SAAS;YACb,OAAO,KAAK,GAAG,OAAO,WAAW,GAAG;YACpC,OAAO,MAAM,GAAG,OAAO,YAAY,GAAG;QACxC;QAEA,MAAM,gBAAgB;YACpB,MAAM,YAAY,IAAI,eAAe,CAAC,OAAO,KAAK,EAAE,OAAO,MAAM;YACjE,MAAM,OAAO,UAAU,IAAI;YAE3B,IAAK,IAAI,IAAI,GAAG,IAAI,KAAK,MAAM,EAAE,KAAK,EAAG;gBACvC,MAAM,QAAQ,KAAK,MAAM,KAAK;gBAC9B,IAAI,CAAC,EAAE,GAAG,OAAM,IAAI;gBACpB,IAAI,CAAC,IAAI,EAAE,GAAG,OAAM,IAAI;gBACxB,IAAI,CAAC,IAAI,EAAE,GAAG,OAAM,IAAI;gBACxB,IAAI,CAAC,IAAI,EAAE,GAAG,KAAI,IAAI;YACxB;YAEA,IAAI,YAAY,CAAC,WAAW,GAAG;QACjC;QAEA,MAAM,UAAU;YACd;YACA,2EAA2E;YAC3E,IAAI,QAAQ,MAAM,GAAG;gBACnB;YACF;YACA,cAAc,sBAAsB;QACtC;QAEA;QACA,OAAO,gBAAgB,CAAC,UAAU;QAClC;QAEA,OAAO;YACL,OAAO,mBAAmB,CAAC,UAAU;YACrC,qBAAqB;QACvB;IACF,GAAG,EAAE;IAEL,qBACE,8OAAC;QACC,KAAK;QACL,WAAW;QACX,OAAO;YACL,UAAU;YACV,OAAO;YACP,OAAO;YACP,QAAQ;YACR,eAAe;YACf;YACA,cAAc;QAChB;;;;;;AAGN"}},
    {"offset": {"line": 279, "column": 0}, "map": {"version":3,"sources":["file:///Users/aarav/Desktop/Neural-Nexus/Frontend/lib/api/sms.ts"],"sourcesContent":["const BASE_URL = \"http://localhost:8000\";\n\nexport async function analyzeSms(data: {\n  text: string;\n  include_llm_explanation?: boolean;\n}) {\n  const res = await fetch(`${BASE_URL}/text/sms/analyze`, {\n    method: \"POST\",\n    headers: { \"Content-Type\": \"application/json\" },\n    credentials: \"include\",\n    body: JSON.stringify(data),\n  });\n  if (!res.ok) throw new Error(await res.text());\n  return res.json();\n}\n"],"names":[],"mappings":";;;;AAAA,MAAM,WAAW;AAEV,eAAe,WAAW,IAGhC;IACC,MAAM,MAAM,MAAM,MAAM,GAAG,SAAS,iBAAiB,CAAC,EAAE;QACtD,QAAQ;QACR,SAAS;YAAE,gBAAgB;QAAmB;QAC9C,aAAa;QACb,MAAM,KAAK,SAAS,CAAC;IACvB;IACA,IAAI,CAAC,IAAI,EAAE,EAAE,MAAM,IAAI,MAAM,MAAM,IAAI,IAAI;IAC3C,OAAO,IAAI,IAAI;AACjB"}},
    {"offset": {"line": 300, "column": 0}, "map": {"version":3,"sources":["file:///Users/aarav/Desktop/Neural-Nexus/Frontend/lib/api/email.ts"],"sourcesContent":["const BASE_URL = \"http://localhost:8000\";\n\nexport async function analyzeEmail(data: {\n  sender: string;\n  subject: string;\n  body: string;\n  with_llm_explanation?: boolean;\n}) {\n  const res = await fetch(`${BASE_URL}/text/email/analyze/extension`, {\n    method: \"POST\",\n    headers: { \"Content-Type\": \"application/json\" },\n    credentials: \"include\",\n    body: JSON.stringify(data),\n  });\n  if (!res.ok) throw new Error(await res.text());\n  return res.json();\n}\n"],"names":[],"mappings":";;;;AAAA,MAAM,WAAW;AAEV,eAAe,aAAa,IAKlC;IACC,MAAM,MAAM,MAAM,MAAM,GAAG,SAAS,6BAA6B,CAAC,EAAE;QAClE,QAAQ;QACR,SAAS;YAAE,gBAAgB;QAAmB;QAC9C,aAAa;QACb,MAAM,KAAK,SAAS,CAAC;IACvB;IACA,IAAI,CAAC,IAAI,EAAE,EAAE,MAAM,IAAI,MAAM,MAAM,IAAI,IAAI;IAC3C,OAAO,IAAI,IAAI;AACjB"}},
