    {"offset": {"line": 342, "column": 0}, "map": {"version":3,"sources":["file:///Users/aarav/Desktop/Neural-Nexus/Frontend/lib/api/voice.ts"],"sourcesContent":["const BASE_URL = \"http://localhost:8000\";\n\nexport async function analyzeVoice(file: File) {\n  const form = new FormData();\n  form.append(\"file\", file);\n\n  const res = await fetch(`${BASE_URL}/voice/analyse`, {\n    method: \"POST\",\n    credentials: \"include\",\n    body: form,\n  });\n  if (!res.ok) throw new Error(await res.text());\n  return res.json();\n}\n"],"names":[],"mappings":";;;;AAAA,MAAM,WAAW;AAEV,eAAe,aAAa,IAAU;IAC3C,MAAM,OAAO,IAAI;IACjB,KAAK,MAAM,CAAC,QAAQ;IAEpB,MAAM,MAAM,MAAM,MAAM,GAAG,SAAS,cAAc,CAAC,EAAE;QACnD,QAAQ;QACR,aAAa;QACb,MAAM;IACR;IACA,IAAI,CAAC,IAAI,EAAE,EAAE,MAAM,IAAI,MAAM,MAAM,IAAI,IAAI;IAC3C,OAAO,IAAI,IAAI;AACjB"}},
    {"offset": {"line": 362, "column": 0}, "map": {"version":3,"sources":["file:///Users/aarav/Desktop/Neural-Nexus/Frontend/lib/api/attachment.ts"],"sourcesContent":["const BASE_URL = \"http://localhost:8000\";\n\nexport async function analyzeAttachment(\n  file: File,\n  withLlmExplanation = false\n) {\n  const form = new FormData();\n  form.append(\"file\", file);\n  form.append(\"with_llm_explanation\", withLlmExplanation ? \"true\" : \"false\");\n\n  const res = await fetch(`${BASE_URL}/attachment/analyze`, {\n    method: \"POST\",\n    credentials: \"include\",\n    body: form,\n  });\n  if (!res.ok) throw new Error(await res.text());\n  return res.json();\n}\n"],"names":[],"mappings":";;;;AAAA,MAAM,WAAW;AAEV,eAAe,kBACpB,IAAU,EACV,qBAAqB,KAAK;IAE1B,MAAM,OAAO,IAAI;IACjB,KAAK,MAAM,CAAC,QAAQ;IACpB,KAAK,MAAM,CAAC,wBAAwB,qBAAqB,SAAS;IAElE,MAAM,MAAM,MAAM,MAAM,GAAG,SAAS,mBAAmB,CAAC,EAAE;QACxD,QAAQ;QACR,aAAa;QACb,MAAM;IACR;IACA,IAAI,CAAC,IAAI,EAAE,EAAE,MAAM,IAAI,MAAM,MAAM,IAAI,IAAI;IAC3C,OAAO,IAAI,IAAI;AACjB"}},
    {"offset": {"line": 383, "column": 0}, "map": {"version":3,"sources":["file:///Users/aarav/Desktop/Neural-Nexus/Frontend/components/AnalysisResult.tsx"],"sourcesContent":["\"use client\"\n\nimport { useEffect, useRef, type ReactNode } from \"react\"\n\n// ─── Shape definitions ──────────────────────────────────────────────────────\n\ninterface Prediction {\n  label?: string\n  confidence?: number\n}\n\ninterface FraudReport {\n  risk_score?: number\n  is_fraud?: boolean\n  system_logic?: string\n  red_flags?: string[]\n}\n\ninterface VoiceAnalysis {\n  result?: string\n  confidence?: number\n}\n\nexport interface AnalysisData {\n  request_id?: string\n  // scores\n  risk_score?: number\n  confidence?: number\n  phishing_probability?: number\n  risk_level?: string\n  // classification\n  fraud_type?: string\n  final_verdict?: string\n  // text signals\n  flags?: string[]\n  explanation?: string\n  llm_explanation?: string\n  llm_confidence?: number\n  // sub-scores\n  nlp_score?: number\n  similarity_score?: number\n  stylometry_score?: number\n  url_risk_score?: number\n  urgency_score?: number\n  // nested shapes (voice / attachment)\n  prediction?: Prediction\n  fraud_report?: FraudReport\n  voice_analysis?: VoiceAnalysis\n  [key: string]: unknown\n}\n\n// ─── Normalize heterogeneous API shapes ─────────────────────────────────────\n\ntype RiskLevel = \"LOW\" | \"MEDIUM\" | \"HIGH\"\n\nfunction deriveLevel(score: number | null, provided?: string): RiskLevel | null {\n  if (provided) {\n    const u = provided.toUpperCase()\n    if (u === \"LOW\" || u === \"MEDIUM\" || u === \"HIGH\") return u as RiskLevel\n  }\n  if (score === null) return null\n  if (score < 0.3) return \"LOW\"\n  if (score <= 0.7) return \"MEDIUM\"\n  return \"HIGH\"\n}\n\nfunction normalize(r: AnalysisData) {\n  const riskScore =\n    typeof r.risk_score === \"number\" ? r.risk_score\n    : typeof r.fraud_report?.risk_score === \"number\" ? r.fraud_report!.risk_score!\n    : typeof r.phishing_probability === \"number\" ? r.phishing_probability\n    : null\n\n  const confidence =\n    typeof r.confidence === \"number\" ? r.confidence\n    : typeof r.llm_confidence === \"number\" ? r.llm_confidence\n    : null\n\n  const fraudType =\n    typeof r.fraud_type === \"string\" ? r.fraud_type\n    : typeof r.final_verdict === \"string\" ? r.final_verdict\n    : typeof r.fraud_report?.is_fraud === \"boolean\"\n      ? (r.fraud_report!.is_fraud ? \"fraud\" : \"clean\")\n    : null\n\n  const predLabel =\n    r.prediction?.label\n    ?? r.voice_analysis?.result\n    ?? null\n\n  const predConfidence =\n    typeof r.prediction?.confidence === \"number\" ? r.prediction!.confidence!\n    : typeof r.voice_analysis?.confidence === \"number\" ? r.voice_analysis!.confidence!\n    : null\n\n  const flags: string[] = [\n    ...(Array.isArray(r.flags) ? (r.flags as string[]) : []),\n    ...(Array.isArray(r.fraud_report?.red_flags) ? r.fraud_report!.red_flags! : []),\n  ]\n\n  const explanation =\n    (typeof r.llm_explanation === \"string\" && r.llm_explanation.trim())\n      ? r.llm_explanation.trim()\n    : (typeof r.explanation === \"string\" && r.explanation.trim())\n      ? r.explanation.trim()\n    : (typeof r.fraud_report?.system_logic === \"string\" && r.fraud_report!.system_logic!.trim())\n      ? r.fraud_report!.system_logic!.trim()\n    : null\n\n  const riskLevel = deriveLevel(riskScore, r.risk_level)\n\n  const nlpScore = typeof r.nlp_score === \"number\" ? r.nlp_score : null\n  const simScore = typeof r.similarity_score === \"number\" ? r.similarity_score : null\n  const styloScore = typeof r.stylometry_score === \"number\" ? r.stylometry_score : null\n  const urlRisk = typeof r.url_risk_score === \"number\" ? r.url_risk_score : null\n  const urgency = typeof r.urgency_score === \"number\" ? r.urgency_score : null\n\n  const hasAdvanced = [nlpScore, simScore, styloScore, urlRisk, urgency].some((v) => v !== null)\n\n  const reqId = typeof r.request_id === \"string\" ? r.request_id : null\n\n  const SAFE_LABELS = new Set([\"safe\", \"clean\", \"ham\", \"real (bonafide)\"])\n  const isThreat = !!fraudType && !SAFE_LABELS.has(fraudType.toLowerCase())\n  const isPredThreat = !!predLabel && !SAFE_LABELS.has(predLabel.toLowerCase())\n\n  return {\n    riskScore,\n    riskLevel,\n    confidence,\n    fraudType,\n    predLabel,\n    predConfidence,\n    flags,\n    explanation,\n    nlpScore,\n    simScore,\n    styloScore,\n    urlRisk,\n    urgency,\n    hasAdvanced,\n    reqId,\n    isThreat,\n    isPredThreat,\n  }\n}\n\n// ─── Formatters ──────────────────────────────────────────────────────────────\n\nconst pct = (n: number | null) => (n === null ? \"—\" : `${(n * 100).toFixed(0)}%`)\nconst f2  = (n: number | null) => (n === null ? \"—\" : n.toFixed(2))\n\n// ─── Risk visual tokens ──────────────────────────────────────────────────────\n\nconst RISK_TEXT: Record<RiskLevel, string> = {\n  LOW:    \"text-foreground/70\",\n  MEDIUM: \"text-accent\",\n  HIGH:   \"text-destructive\",\n}\n\nconst RISK_BORDER: Record<RiskLevel, string> = {\n  LOW:    \"border-border/35\",\n  MEDIUM: \"border-accent/45\",\n  HIGH:   \"border-destructive/55\",\n}\n\nconst RISK_BAR: Record<RiskLevel, string> = {\n  LOW:    \"bg-foreground/40\",\n  MEDIUM: \"bg-accent/75\",\n  HIGH:   \"bg-destructive/85\",\n}\n\nconst RISK_FLAG_BORDER: Record<RiskLevel, string> = {\n  LOW:    \"border-border/30\",\n  MEDIUM: \"border-accent/35\",\n  HIGH:   \"border-destructive/45\",\n}\n\n// ─── Internal atoms ──────────────────────────────────────────────────────────\n\nfunction Divider() {\n  return <div className=\"border-b border-border/15\" />\n}\n\nfunction SectionLabel({ children }: { children: ReactNode }) {\n  return (\n    <p className=\"font-mono text-[9px] uppercase tracking-[0.45em] text-muted-foreground/55 mb-4\">\n      {children}\n    </p>\n  )\n}\n\nfunction CoreMetric({ label, value, accent = false }: { label: string; value: string; accent?: boolean }) {\n  return (\n    <div>\n      <p className=\"font-mono text-[8px] uppercase tracking-[0.35em] text-muted-foreground/50 mb-1.5\">\n        {label}\n      </p>\n      <p className={`font-mono text-sm tracking-[0.03em] ${accent ? \"text-accent\" : \"text-foreground/90\"}`}>\n        {value}\n      </p>\n    </div>\n  )\n}\n\nfunction TinySignal({ label, value }: { label: string; value: string }) {\n  return (\n    <div className=\"flex items-baseline gap-1.5\">\n      <span className=\"font-mono text-[8px] uppercase tracking-[0.25em] text-muted-foreground/40\">\n        {label}\n      </span>\n      <span className=\"font-mono text-[10px] text-muted-foreground/60\">{value}</span>\n    </div>\n  )\n}\n\n// ─── Main component ───────────────────────────────────────────────────────────\n\nexport function AnalysisResult({ data }: { data: AnalysisData }) {\n  const rootRef = useRef<HTMLDivElement>(null)\n  const d = normalize(data)\n\n  // Smooth entrance — no library required\n  useEffect(() => {\n    const el = rootRef.current\n    if (!el) return\n    el.style.opacity = \"0\"\n    el.style.transform = \"translateY(10px)\"\n    const raf = requestAnimationFrame(() => {\n      el.style.transition =\n        \"opacity 0.55s cubic-bezier(0.16,1,0.3,1), transform 0.55s cubic-bezier(0.16,1,0.3,1)\"\n      el.style.opacity = \"1\"\n      el.style.transform = \"translateY(0)\"\n    })\n    return () => cancelAnimationFrame(raf)\n  }, [])\n\n  const riskText      = d.riskLevel ? RISK_TEXT[d.riskLevel]       : \"text-foreground/50\"\n  const riskBorder    = d.riskLevel ? RISK_BORDER[d.riskLevel]     : \"border-border/25\"\n  const riskBar       = d.riskLevel ? RISK_BAR[d.riskLevel]        : \"bg-foreground/30\"\n  const riskFlagBorder = d.riskLevel ? RISK_FLAG_BORDER[d.riskLevel] : \"border-border/30\"\n\n  return (\n    <div ref={rootRef} className={`border ${riskBorder} mt-8`}>\n\n      {/* ── Header ─────────────────────────────────────────────────────────── */}\n      <div className=\"flex items-center justify-between px-5 py-3\">\n        <span className=\"font-mono text-[9px] uppercase tracking-[0.45em] text-muted-foreground/55\">\n          Threat Assessment\n        </span>\n        {d.reqId && (\n          <span className=\"font-mono text-[8px] text-muted-foreground/35 tracking-[0.15em]\">\n            {d.reqId.slice(0, 8).toUpperCase()}\n          </span>\n        )}\n      </div>\n      <Divider />\n\n      {/* ── 1. Primary Signal ───────────────────────────────────────────────── */}\n      <div className=\"px-5 pt-8 pb-5\">\n        <SectionLabel>Risk Level</SectionLabel>\n        <div className=\"flex items-end gap-3\">\n          {d.riskLevel === \"HIGH\" && (\n            <span className=\"inline-block w-1.5 h-1.5 bg-destructive self-center shrink-0 animate-pulse mb-1\" />\n          )}\n          {d.riskLevel === \"MEDIUM\" && (\n            <span className=\"inline-block w-1.5 h-1.5 bg-accent self-center shrink-0 mb-1\" />\n          )}\n          <span\n            className={`font-[var(--font-bebas)] text-6xl md:text-7xl leading-none tracking-tight ${riskText}`}\n          >\n            {d.riskLevel ?? \"UNKNOWN\"}\n          </span>\n          {d.riskScore !== null && (\n            <span className=\"font-mono text-[10px] text-muted-foreground/50 mb-1.5 tracking-[0.1em]\">\n              {pct(d.riskScore)} raw\n            </span>\n          )}\n        </div>\n\n        {/* ── Risk Score Bar ────────────────────────────────────────────────── */}\n        {d.riskScore !== null && (\n          <div className=\"mt-5 h-px bg-border/20 relative overflow-hidden\">\n            <div\n              className={`absolute inset-y-0 left-0 ${riskBar} transition-all duration-700 ease-out`}\n              style={{ width: `${(d.riskScore * 100).toFixed(0)}%` }}\n            />\n          </div>\n        )}\n      </div>\n      <Divider />\n\n      {/* ── 2. Core Metrics ─────────────────────────────────────────────────── */}\n      <div className=\"px-5 py-6\">\n        <SectionLabel>Core Metrics</SectionLabel>\n        <div className=\"grid grid-cols-2 md:grid-cols-4 gap-x-6 gap-y-5\">\n          <CoreMetric label=\"Risk Score\"  value={pct(d.riskScore)} />\n          <CoreMetric label=\"Confidence\"  value={pct(d.confidence)} />\n          <CoreMetric\n            label=\"Prediction\"\n            value={d.predLabel ? d.predLabel.toUpperCase() : \"—\"}\n            accent={d.isPredThreat}\n          />\n          <CoreMetric\n            label=\"Fraud Type\"\n            value={d.fraudType ? d.fraudType.toUpperCase() : \"—\"}\n            accent={d.isThreat}\n          />\n        </div>\n      </div>\n      <Divider />\n\n      {/* ── 3. Active Signals ───────────────────────────────────────────────── */}\n      <div className=\"px-5 py-6\">\n        <SectionLabel>\n          {d.flags.length > 0 ? `Active Signals [${d.flags.length}]` : \"Active Signals\"}\n        </SectionLabel>\n        {d.flags.length > 0 ? (\n          <div className=\"flex flex-wrap gap-2\">\n            {d.flags.map((flag, i) => (\n              <span\n                key={i}\n                className={`font-mono text-[9px] uppercase tracking-[0.15em] border ${riskFlagBorder} px-2.5 py-1 text-muted-foreground/70`}\n              >\n                {flag.replace(/_/g, \" \")}\n              </span>\n            ))}\n          </div>\n        ) : (\n          <p className=\"font-mono text-[10px] text-muted-foreground/45 tracking-[0.1em]\">\n            No active threat indicators\n          </p>\n        )}\n      </div>\n\n      {/* ── 4. Explanation ──────────────────────────────────────────────────── */}\n      {d.explanation && (\n        <>\n          <Divider />\n          <div className=\"px-5 py-6\">\n            <SectionLabel>Analysis Report //</SectionLabel>\n            <p className=\"font-mono text-[11px] text-muted-foreground/75 leading-relaxed max-w-prose\">\n              {d.explanation}\n            </p>\n          </div>\n        </>\n      )}\n\n      {/* ── 5. Extended Telemetry ───────────────────────────────────────────── */}\n      {d.hasAdvanced && (\n        <>\n          <Divider />\n          <div className=\"px-5 py-4\">\n            <SectionLabel>Extended Telemetry</SectionLabel>\n            <div className=\"flex flex-wrap gap-x-6 gap-y-2\">\n              {d.nlpScore   !== null && <TinySignal label=\"NLP\"        value={f2(d.nlpScore)} />}\n              {d.simScore   !== null && <TinySignal label=\"Similarity\" value={f2(d.simScore)} />}\n              {d.styloScore !== null && <TinySignal label=\"Stylometry\" value={f2(d.styloScore)} />}\n              {d.urlRisk    !== null && <TinySignal label=\"URL Risk\"   value={f2(d.urlRisk)} />}\n              {d.urgency    !== null && <TinySignal label=\"Urgency\"    value={f2(d.urgency)} />}\n            </div>\n          </div>\n        </>\n      )}\n\n    </div>\n  )\n}\n"],"names":[],"mappings":";;;;;AAEA;AAFA;;;AAuDA,SAAS,YAAY,KAAoB,EAAE,QAAiB;IAC1D,IAAI,UAAU;QACZ,MAAM,IAAI,SAAS,WAAW;QAC9B,IAAI,MAAM,SAAS,MAAM,YAAY,MAAM,QAAQ,OAAO;IAC5D;IACA,IAAI,UAAU,MAAM,OAAO;IAC3B,IAAI,QAAQ,KAAK,OAAO;IACxB,IAAI,SAAS,KAAK,OAAO;IACzB,OAAO;AACT;AAEA,SAAS,UAAU,CAAe;IAChC,MAAM,YACJ,OAAO,EAAE,UAAU,KAAK,WAAW,EAAE,UAAU,GAC7C,OAAO,EAAE,YAAY,EAAE,eAAe,WAAW,EAAE,YAAY,CAAE,UAAU,GAC3E,OAAO,EAAE,oBAAoB,KAAK,WAAW,EAAE,oBAAoB,GACnE;IAEJ,MAAM,aACJ,OAAO,EAAE,UAAU,KAAK,WAAW,EAAE,UAAU,GAC7C,OAAO,EAAE,cAAc,KAAK,WAAW,EAAE,cAAc,GACvD;IAEJ,MAAM,YACJ,OAAO,EAAE,UAAU,KAAK,WAAW,EAAE,UAAU,GAC7C,OAAO,EAAE,aAAa,KAAK,WAAW,EAAE,aAAa,GACrD,OAAO,EAAE,YAAY,EAAE,aAAa,YACjC,EAAE,YAAY,CAAE,QAAQ,GAAG,UAAU,UACxC;IAEJ,MAAM,YACJ,EAAE,UAAU,EAAE,SACX,EAAE,cAAc,EAAE,UAClB;IAEL,MAAM,iBACJ,OAAO,EAAE,UAAU,EAAE,eAAe,WAAW,EAAE,UAAU,CAAE,UAAU,GACrE,OAAO,EAAE,cAAc,EAAE,eAAe,WAAW,EAAE,cAAc,CAAE,UAAU,GAC/E;IAEJ,MAAM,QAAkB;WAClB,MAAM,OAAO,CAAC,EAAE,KAAK,IAAK,EAAE,KAAK,GAAgB,EAAE;WACnD,MAAM,OAAO,CAAC,EAAE,YAAY,EAAE,aAAa,EAAE,YAAY,CAAE,SAAS,GAAI,EAAE;KAC/E;IAED,MAAM,cACJ,AAAC,OAAO,EAAE,eAAe,KAAK,YAAY,EAAE,eAAe,CAAC,IAAI,KAC5D,EAAE,eAAe,CAAC,IAAI,KACxB,AAAC,OAAO,EAAE,WAAW,KAAK,YAAY,EAAE,WAAW,CAAC,IAAI,KACtD,EAAE,WAAW,CAAC,IAAI,KACpB,AAAC,OAAO,EAAE,YAAY,EAAE,iBAAiB,YAAY,EAAE,YAAY,CAAE,YAAY,CAAE,IAAI,KACrF,EAAE,YAAY,CAAE,YAAY,CAAE,IAAI,KACpC;IAEJ,MAAM,YAAY,YAAY,WAAW,EAAE,UAAU;IAErD,MAAM,WAAW,OAAO,EAAE,SAAS,KAAK,WAAW,EAAE,SAAS,GAAG;IACjE,MAAM,WAAW,OAAO,EAAE,gBAAgB,KAAK,WAAW,EAAE,gBAAgB,GAAG;IAC/E,MAAM,aAAa,OAAO,EAAE,gBAAgB,KAAK,WAAW,EAAE,gBAAgB,GAAG;IACjF,MAAM,UAAU,OAAO,EAAE,cAAc,KAAK,WAAW,EAAE,cAAc,GAAG;IAC1E,MAAM,UAAU,OAAO,EAAE,aAAa,KAAK,WAAW,EAAE,aAAa,GAAG;IAExE,MAAM,cAAc;QAAC;QAAU;QAAU;QAAY;QAAS;KAAQ,CAAC,IAAI,CAAC,CAAC,IAAM,MAAM;IAEzF,MAAM,QAAQ,OAAO,EAAE,UAAU,KAAK,WAAW,EAAE,UAAU,GAAG;IAEhE,MAAM,cAAc,IAAI,IAAI;QAAC;QAAQ;QAAS;QAAO;KAAkB;IACvE,MAAM,WAAW,CAAC,CAAC,aAAa,CAAC,YAAY,GAAG,CAAC,UAAU,WAAW;IACtE,MAAM,eAAe,CAAC,CAAC,aAAa,CAAC,YAAY,GAAG,CAAC,UAAU,WAAW;IAE1E,OAAO;QACL;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;QACA;IACF;AACF;AAEA,gFAAgF;AAEhF,MAAM,MAAM,CAAC,IAAsB,MAAM,OAAO,MAAM,GAAG,CAAC,IAAI,GAAG,EAAE,OAAO,CAAC,GAAG,CAAC,CAAC;AAChF,MAAM,KAAM,CAAC,IAAsB,MAAM,OAAO,MAAM,EAAE,OAAO,CAAC;AAEhE,gFAAgF;AAEhF,MAAM,YAAuC;IAC3C,KAAQ;IACR,QAAQ;IACR,MAAQ;AACV;AAEA,MAAM,cAAyC;IAC7C,KAAQ;IACR,QAAQ;IACR,MAAQ;AACV;AAEA,MAAM,WAAsC;IAC1C,KAAQ;IACR,QAAQ;IACR,MAAQ;AACV;AAEA,MAAM,mBAA8C;IAClD,KAAQ;IACR,QAAQ;IACR,MAAQ;AACV;AAEA,gFAAgF;AAEhF,SAAS;IACP,qBAAO,8OAAC;QAAI,WAAU;;;;;;AACxB;AAEA,SAAS,aAAa,EAAE,QAAQ,EAA2B;IACzD,qBACE,8OAAC;QAAE,WAAU;kBACV;;;;;;AAGP;AAEA,SAAS,WAAW,EAAE,KAAK,EAAE,KAAK,EAAE,SAAS,KAAK,EAAsD;IACtG,qBACE,8OAAC;;0BACC,8OAAC;gBAAE,WAAU;0BACV;;;;;;0BAEH,8OAAC;gBAAE,WAAW,CAAC,oCAAoC,EAAE,SAAS,gBAAgB,sBAAsB;0BACjG;;;;;;;;;;;;AAIT;AAEA,SAAS,WAAW,EAAE,KAAK,EAAE,KAAK,EAAoC;IACpE,qBACE,8OAAC;QAAI,WAAU;;0BACb,8OAAC;gBAAK,WAAU;0BACb;;;;;;0BAEH,8OAAC;gBAAK,WAAU;0BAAkD;;;;;;;;;;;;AAGxE;AAIO,SAAS,eAAe,EAAE,IAAI,EAA0B;IAC7D,MAAM,UAAU,IAAA,+MAAM,EAAiB;IACvC,MAAM,IAAI,UAAU;IAEpB,wCAAwC;IACxC,IAAA,kNAAS,EAAC;QACR,MAAM,KAAK,QAAQ,OAAO;QAC1B,IAAI,CAAC,IAAI;QACT,GAAG,KAAK,CAAC,OAAO,GAAG;QACnB,GAAG,KAAK,CAAC,SAAS,GAAG;QACrB,MAAM,MAAM,sBAAsB;YAChC,GAAG,KAAK,CAAC,UAAU,GACjB;YACF,GAAG,KAAK,CAAC,OAAO,GAAG;YACnB,GAAG,KAAK,CAAC,SAAS,GAAG;QACvB;QACA,OAAO,IAAM,qBAAqB;IACpC,GAAG,EAAE;IAEL,MAAM,WAAgB,EAAE,SAAS,GAAG,SAAS,CAAC,EAAE,SAAS,CAAC,GAAS;IACnE,MAAM,aAAgB,EAAE,SAAS,GAAG,WAAW,CAAC,EAAE,SAAS,CAAC,GAAO;IACnE,MAAM,UAAgB,EAAE,SAAS,GAAG,QAAQ,CAAC,EAAE,SAAS,CAAC,GAAU;IACnE,MAAM,iBAAiB,EAAE,SAAS,GAAG,gBAAgB,CAAC,EAAE,SAAS,CAAC,GAAG;IAErE,qBACE,8OAAC;QAAI,KAAK;QAAS,WAAW,CAAC,OAAO,EAAE,WAAW,KAAK,CAAC;;0BAGvD,8OAAC;gBAAI,WAAU;;kCACb,8OAAC;wBAAK,WAAU;kCAA4E;;;;;;oBAG3F,EAAE,KAAK,kBACN,8OAAC;wBAAK,WAAU;kCACb,EAAE,KAAK,CAAC,KAAK,CAAC,GAAG,GAAG,WAAW;;;;;;;;;;;;0BAItC,8OAAC;;;;;0BAGD,8OAAC;gBAAI,WAAU;;kCACb,8OAAC;kCAAa;;;;;;kCACd,8OAAC;wBAAI,WAAU;;4BACZ,EAAE,SAAS,KAAK,wBACf,8OAAC;gCAAK,WAAU;;;;;;4BAEjB,EAAE,SAAS,KAAK,0BACf,8OAAC;gCAAK,WAAU;;;;;;0CAElB,8OAAC;gCACC,WAAW,CAAC,0EAA0E,EAAE,UAAU;0CAEjG,EAAE,SAAS,IAAI;;;;;;4BAEjB,EAAE,SAAS,KAAK,sBACf,8OAAC;gCAAK,WAAU;;oCACb,IAAI,EAAE,SAAS;oCAAE;;;;;;;;;;;;;oBAMvB,EAAE,SAAS,KAAK,sBACf,8OAAC;wBAAI,WAAU;kCACb,cAAA,8OAAC;4BACC,WAAW,CAAC,0BAA0B,EAAE,QAAQ,qCAAqC,CAAC;4BACtF,OAAO;gCAAE,OAAO,GAAG,CAAC,EAAE,SAAS,GAAG,GAAG,EAAE,OAAO,CAAC,GAAG,CAAC,CAAC;4BAAC;;;;;;;;;;;;;;;;;0BAK7D,8OAAC;;;;;0BAGD,8OAAC;gBAAI,WAAU;;kCACb,8OAAC;kCAAa;;;;;;kCACd,8OAAC;wBAAI,WAAU;;0CACb,8OAAC;gCAAW,OAAM;gCAAc,OAAO,IAAI,EAAE,SAAS;;;;;;0CACtD,8OAAC;gCAAW,OAAM;gCAAc,OAAO,IAAI,EAAE,UAAU;;;;;;0CACvD,8OAAC;gCACC,OAAM;gCACN,OAAO,EAAE,SAAS,GAAG,EAAE,SAAS,CAAC,WAAW,KAAK;gCACjD,QAAQ,EAAE,YAAY;;;;;;0CAExB,8OAAC;gCACC,OAAM;gCACN,OAAO,EAAE,SAAS,GAAG,EAAE,SAAS,CAAC,WAAW,KAAK;gCACjD,QAAQ,EAAE,QAAQ;;;;;;;;;;;;;;;;;;0BAIxB,8OAAC;;;;;0BAGD,8OAAC;gBAAI,WAAU;;kCACb,8OAAC;kCACE,EAAE,KAAK,CAAC,MAAM,GAAG,IAAI,CAAC,gBAAgB,EAAE,EAAE,KAAK,CAAC,MAAM,CAAC,CAAC,CAAC,GAAG;;;;;;oBAE9D,EAAE,KAAK,CAAC,MAAM,GAAG,kBAChB,8OAAC;wBAAI,WAAU;kCACZ,EAAE,KAAK,CAAC,GAAG,CAAC,CAAC,MAAM,kBAClB,8OAAC;gCAEC,WAAW,CAAC,wDAAwD,EAAE,eAAe,qCAAqC,CAAC;0CAE1H,KAAK,OAAO,CAAC,MAAM;+BAHf;;;;;;;;;6CAQX,8OAAC;wBAAE,WAAU;kCAAkE;;;;;;;;;;;;YAOlF,EAAE,WAAW,kBACZ;;kCACE,8OAAC;;;;;kCACD,8OAAC;wBAAI,WAAU;;0CACb,8OAAC;0CAAa;;;;;;0CACd,8OAAC;gCAAE,WAAU;0CACV,EAAE,WAAW;;;;;;;;;;;;;;YAOrB,EAAE,WAAW,kBACZ;;kCACE,8OAAC;;;;;kCACD,8OAAC;wBAAI,WAAU;;0CACb,8OAAC;0CAAa;;;;;;0CACd,8OAAC;gCAAI,WAAU;;oCACZ,EAAE,QAAQ,KAAO,sBAAQ,8OAAC;wCAAW,OAAM;wCAAa,OAAO,GAAG,EAAE,QAAQ;;;;;;oCAC5E,EAAE,QAAQ,KAAO,sBAAQ,8OAAC;wCAAW,OAAM;wCAAa,OAAO,GAAG,EAAE,QAAQ;;;;;;oCAC5E,EAAE,UAAU,KAAK,sBAAQ,8OAAC;wCAAW,OAAM;wCAAa,OAAO,GAAG,EAAE,UAAU;;;;;;oCAC9E,EAAE,OAAO,KAAQ,sBAAQ,8OAAC;wCAAW,OAAM;wCAAa,OAAO,GAAG,EAAE,OAAO;;;;;;oCAC3E,EAAE,OAAO,KAAQ,sBAAQ,8OAAC;wCAAW,OAAM;wCAAa,OAAO,GAAG,EAAE,OAAO;;;;;;;;;;;;;;;;;;;;;;;;;;AAQ1F"}},
    {"offset": {"line": 906, "column": 0}, "map": {"version":3,"sources":["file:///Users/aarav/Desktop/Neural-Nexus/Frontend/app/dashboard/page.tsx"],"sourcesContent":["\"use client\"\n\nimport { useRef, useEffect, useState, useCallback, useMemo } from \"react\"\nimport Link from \"next/link\"\nimport { Input } from \"@/components/ui/input\"\nimport { ScrambleTextOnHover } from \"@/components/scramble-text\"\nimport { BitmapChevron } from \"@/components/bitmap-chevron\"\nimport { AnimatedNoise } from \"@/components/animated-noise\"\nimport gsap from \"gsap\"\nimport { analyzeSms } from \"@/lib/api/sms\"\nimport { analyzeEmail } from \"@/lib/api/email\"\nimport { analyzeUrl } from \"@/lib/api/url\"\nimport { analyzeVoice } from \"@/lib/api/voice\"\nimport { analyzeAttachment } from \"@/lib/api/attachment\"\nimport { AnalysisResult, type AnalysisData } from \"@/components/AnalysisResult\"\n\n// ─── Shared input style ───────────────────────────────────────────────────────\n\nconst INPUT_CLS =\n  \"bg-transparent border-t-0 border-l-0 border-r-0 border-b border-border/50 rounded-none h-14 px-0 font-mono text-sm focus-visible:ring-0 focus-visible:border-accent transition-all duration-500 placeholder:text-muted-foreground/50 text-foreground/90\"\n\n// ─── Error block ──────────────────────────────────────────────────────────────\n\nfunction ErrorBlock({ message }: { message: string }) {\n  return (\n    <div className=\"border border-destructive/45 px-5 py-4 mt-6 font-mono text-[10px] text-destructive/90 leading-relaxed\">\n      <span className=\"text-destructive/70 uppercase tracking-[0.3em]\">Error // </span>\n      {message}\n    </div>\n  )\n}\n\n// ─── Execute button ───────────────────────────────────────────────────────────\n\nfunction ExecuteButton({\n  onClick,\n  loading,\n  disabled,\n}: {\n  onClick: () => void\n  loading: boolean\n  disabled: boolean\n}) {\n  return (\n    <button\n      onClick={onClick}\n      disabled={disabled || loading}\n      className=\"group/btn inline-flex items-center gap-6 border border-foreground/25 px-8 py-4 font-mono text-[10px] uppercase tracking-[0.3em] text-foreground/85 hover:border-accent hover:text-accent hover:bg-accent/5 transition-all duration-300 disabled:opacity-35 disabled:cursor-not-allowed active:scale-[0.98]\"\n    >\n      <ScrambleTextOnHover\n        text={loading ? \"Processing...\" : \"Execute Analysis\"}\n        as=\"span\"\n        duration={0.5}\n      />\n      <BitmapChevron className=\"transition-transform duration-500 ease-in-out group-hover/btn:rotate-45\" />\n    </button>\n  )\n}\n\n// ─── Section header ───────────────────────────────────────────────────────────\n\nfunction SectionHeader({\n  index,\n  title,\n  description,\n}: {\n  index: string\n  title: string\n  description: string\n}) {\n  return (\n    <>\n      <div className=\"flex items-baseline gap-4 mb-8\">\n        <span className=\"font-mono text-[10px] text-accent border border-accent/35 px-2 py-1 shrink-0\">\n          {index}\n        </span>\n        <h2 className=\"font-[var(--font-bebas)] text-4xl md:text-5xl tracking-tight group-hover:text-accent transition-colors duration-300\">\n          {title}\n        </h2>\n      </div>\n      <p className=\"font-mono text-xs text-muted-foreground/80 mb-10 leading-relaxed max-w-sm\">\n        {description}\n      </p>\n    </>\n  )\n}\n\n// ─── File input row ───────────────────────────────────────────────────────────\n\nfunction FileInputRow({\n  file,\n  placeholder,\n  accept,\n  onFile,\n}: {\n  file: File | null\n  placeholder: string\n  accept?: string\n  onFile: (f: File | null) => void\n}) {\n  return (\n    <div className=\"relative border-b border-border/50\">\n      <label className=\"flex items-center h-14 px-0 font-mono text-sm cursor-pointer\">\n        <input\n          type=\"file\"\n          accept={accept}\n          className=\"sr-only\"\n          onChange={(e) => onFile(e.target.files?.[0] ?? null)}\n        />\n        {file ? (\n          <span className=\"text-accent/85\">{file.name}</span>\n        ) : (\n          <span className=\"text-muted-foreground/50\">{placeholder}</span>\n        )}\n      </label>\n      <div className=\"absolute bottom-0 left-0 h-[2px] w-0 bg-accent transition-all duration-700 group-focus-within:w-full\" />\n    </div>\n  )\n}\n\n// ─── Analytics strip ─────────────────────────────────────────────────────────\n\ninterface AnalyticsStat {\n  label: string\n  value: string\n  sub: string\n  accent?: boolean\n}\n\nfunction AnalyticsStrip({\n  analysisCount,\n  threatCount,\n  cleanCount,\n}: {\n  analysisCount: number\n  threatCount: number\n  cleanCount: number\n}) {\n  const stats: AnalyticsStat[] = [\n    {\n      label: \"Engines Online\",\n      value: \"5 / 5\",\n      sub: \"SMS · Email · URL · Voice · File\",\n    },\n    {\n      label: \"Models Active\",\n      value: \"3\",\n      sub: \"NLP · BiLSTM · Claude LLM\",\n      accent: true,\n    },\n    {\n      label: \"Session Analyses\",\n      value: analysisCount === 0 ? \"—\" : String(analysisCount),\n      sub: analysisCount === 0 ? \"Awaiting first scan\" : `${threatCount} threat · ${cleanCount} clean`,\n    },\n    {\n      label: \"Detection Rate\",\n      value: \"99.2%\",\n      sub: \"30-day rolling baseline\",\n    },\n    {\n      label: \"Avg Latency\",\n      value: \"340ms\",\n      sub: \"Peak mesh efficiency\",\n    },\n  ]\n\n  return (\n    <div className=\"mb-20 border border-border/30\">\n      {/* Strip header */}\n      <div className=\"px-5 py-3 border-b border-border/20 flex items-center gap-4\">\n        <span className=\"font-mono text-[9px] uppercase tracking-[0.45em] text-muted-foreground/65\">\n          System Intelligence\n        </span>\n        <span className=\"h-px flex-1 bg-border/20\" />\n        <span className=\"font-mono text-[8px] text-accent uppercase tracking-[0.3em] flex items-center gap-1.5\">\n          <span className=\"inline-block w-1 h-1 bg-accent animate-pulse\" />\n          Live\n        </span>\n      </div>\n\n      {/* Stats grid */}\n      <div className=\"grid grid-cols-2 md:grid-cols-5 divide-y md:divide-y-0 md:divide-x divide-border/20\">\n        {stats.map(({ label, value, sub, accent }) => (\n          <div key={label} className=\"px-5 py-5\">\n            <p className=\"font-mono text-[8px] uppercase tracking-[0.35em] text-muted-foreground/55 mb-2\">\n              {label}\n            </p>\n            <p\n              className={`font-[var(--font-bebas)] text-3xl tracking-tight mb-1 ${\n                accent ? \"text-accent\" : \"text-foreground/92\"\n              }`}\n            >\n              {value}\n            </p>\n            <p className=\"font-mono text-[8px] text-muted-foreground/50 tracking-[0.12em]\">{sub}</p>\n          </div>\n        ))}\n      </div>\n    </div>\n  )\n}\n\n// ─── Channel status row ───────────────────────────────────────────────────────\n\nfunction ChannelStatus({\n  results,\n}: {\n  results: Array<{ label: string; result: AnalysisData | null; loading: boolean }>\n}) {\n  return (\n    <div className=\"mb-20 border border-border/20 px-5 py-4\">\n      <p className=\"font-mono text-[9px] uppercase tracking-[0.45em] text-muted-foreground/55 mb-4\">\n        Channel Status\n      </p>\n      <div className=\"flex flex-wrap gap-x-8 gap-y-3\">\n        {results.map(({ label, result, loading }) => {\n          const color = loading\n            ? \"bg-accent animate-pulse\"\n            : result\n            ? \"bg-foreground/70\"\n            : \"bg-border/50\"\n\n          const textColor = loading\n            ? \"text-accent\"\n            : result\n            ? \"text-foreground/80\"\n            : \"text-muted-foreground/50\"\n\n          const status = loading ? \"Scanning...\" : result ? \"Analyzed\" : \"Standby\"\n\n          return (\n            <div key={label} className=\"flex items-center gap-2\">\n              <span className={`inline-block w-1 h-1 shrink-0 ${color}`} />\n              <span className={`font-mono text-[9px] uppercase tracking-[0.25em] ${textColor}`}>\n                {label}\n              </span>\n              <span className=\"font-mono text-[8px] text-muted-foreground/40 tracking-[0.15em]\">\n                [{status}]\n              </span>\n            </div>\n          )\n        })}\n      </div>\n    </div>\n  )\n}\n\n// ─── Page ─────────────────────────────────────────────────────────────────────\n\nexport default function DashboardPage() {\n  const containerRef = useRef<HTMLDivElement>(null)\n\n  // SMS\n  const [smsText, setSmsText] = useState(\"\")\n  const [smsLoading, setSmsLoading] = useState(false)\n  const [smsResult, setSmsResult] = useState<AnalysisData | null>(null)\n  const [smsError, setSmsError] = useState<string | null>(null)\n\n  // Email\n  const [emailSender, setEmailSender] = useState(\"\")\n  const [emailSubject, setEmailSubject] = useState(\"\")\n  const [emailBody, setEmailBody] = useState(\"\")\n  const [emailLoading, setEmailLoading] = useState(false)\n  const [emailResult, setEmailResult] = useState<AnalysisData | null>(null)\n  const [emailError, setEmailError] = useState<string | null>(null)\n\n  // URL\n  const [urlValue, setUrlValue] = useState(\"\")\n  const [urlLoading, setUrlLoading] = useState(false)\n  const [urlResult, setUrlResult] = useState<AnalysisData | null>(null)\n  const [urlError, setUrlError] = useState<string | null>(null)\n\n  // Voice\n  const [voiceFile, setVoiceFile] = useState<File | null>(null)\n  const [voiceLoading, setVoiceLoading] = useState(false)\n  const [voiceResult, setVoiceResult] = useState<AnalysisData | null>(null)\n  const [voiceError, setVoiceError] = useState<string | null>(null)\n\n  // Attachment\n  const [attachFile, setAttachFile] = useState<File | null>(null)\n  const [attachLoading, setAttachLoading] = useState(false)\n  const [attachResult, setAttachResult] = useState<AnalysisData | null>(null)\n  const [attachError, setAttachError] = useState<string | null>(null)\n\n  // ── Session analytics ──────────────────────────────────────────────────────\n\n  const allResults = useMemo(\n    () => [smsResult, emailResult, urlResult, voiceResult, attachResult],\n    [smsResult, emailResult, urlResult, voiceResult, attachResult],\n  )\n\n  const analysisCount = allResults.filter(Boolean).length\n\n  const threatCount = allResults.filter((r) => {\n    if (!r) return false\n    const score =\n      typeof r.risk_score === \"number\"\n        ? r.risk_score\n        : typeof r.phishing_probability === \"number\"\n        ? r.phishing_probability\n        : 0\n    return score > 0.3\n  }).length\n\n  const cleanCount = analysisCount - threatCount\n\n  const channelStatuses = [\n    { label: \"SMS\", result: smsResult, loading: smsLoading },\n    { label: \"Email\", result: emailResult, loading: emailLoading },\n    { label: \"URL\", result: urlResult, loading: urlLoading },\n    { label: \"Voice\", result: voiceResult, loading: voiceLoading },\n    { label: \"File\", result: attachResult, loading: attachLoading },\n  ]\n\n  // ── GSAP entrance ──────────────────────────────────────────────────────────\n\n  useEffect(() => {\n    if (!containerRef.current) return\n    const ctx = gsap.context(() => {\n      gsap.from(\".dashboard-section\", {\n        y: 40,\n        opacity: 0,\n        duration: 0.8,\n        stagger: 0.15,\n        ease: \"power3.out\",\n      })\n      gsap.from(\".dashboard-header\", {\n        x: -40,\n        opacity: 0,\n        duration: 1,\n        ease: \"power3.out\",\n      })\n      gsap.from(\".analytics-strip\", {\n        y: 20,\n        opacity: 0,\n        duration: 0.6,\n        delay: 0.4,\n        ease: \"power3.out\",\n      })\n    }, containerRef)\n    return () => ctx.revert()\n  }, [])\n\n  // ── Handlers ───────────────────────────────────────────────────────────────\n\n  const handleSms = useCallback(async () => {\n    if (!smsText.trim()) return\n    setSmsLoading(true); setSmsResult(null); setSmsError(null)\n    try {\n      setSmsResult(await analyzeSms({ text: smsText, include_llm_explanation: false }))\n    } catch (err: unknown) {\n      setSmsError(err instanceof Error ? err.message : \"Analysis failed\")\n    } finally {\n      setSmsLoading(false)\n    }\n  }, [smsText])\n\n  const handleEmail = useCallback(async () => {\n    if (!emailSender.trim() || !emailBody.trim()) return\n    setEmailLoading(true); setEmailResult(null); setEmailError(null)\n    try {\n      setEmailResult(\n        await analyzeEmail({\n          sender: emailSender,\n          subject: emailSubject,\n          body: emailBody,\n          with_llm_explanation: false,\n        }),\n      )\n    } catch (err: unknown) {\n      setEmailError(err instanceof Error ? err.message : \"Analysis failed\")\n    } finally {\n      setEmailLoading(false)\n    }\n  }, [emailSender, emailSubject, emailBody])\n\n  const handleUrl = useCallback(async () => {\n    if (!urlValue.trim()) return\n    setUrlLoading(true); setUrlResult(null); setUrlError(null)\n    try {\n      setUrlResult(await analyzeUrl({ url: urlValue, with_llm_explanation: false }))\n    } catch (err: unknown) {\n      setUrlError(err instanceof Error ? err.message : \"Analysis failed\")\n    } finally {\n      setUrlLoading(false)\n    }\n  }, [urlValue])\n\n  const handleVoice = useCallback(async () => {\n    if (!voiceFile) return\n    setVoiceLoading(true); setVoiceResult(null); setVoiceError(null)\n    try {\n      setVoiceResult(await analyzeVoice(voiceFile))\n    } catch (err: unknown) {\n      setVoiceError(err instanceof Error ? err.message : \"Analysis failed\")\n    } finally {\n      setVoiceLoading(false)\n    }\n  }, [voiceFile])\n\n  const handleAttachment = useCallback(async () => {\n    if (!attachFile) return\n    setAttachLoading(true); setAttachResult(null); setAttachError(null)\n    try {\n      setAttachResult(await analyzeAttachment(attachFile, false))\n    } catch (err: unknown) {\n      setAttachError(err instanceof Error ? err.message : \"Analysis failed\")\n    } finally {\n      setAttachLoading(false)\n    }\n  }, [attachFile])\n\n  // ── Render ─────────────────────────────────────────────────────────────────\n\n  return (\n    <main\n      ref={containerRef}\n      className=\"relative min-h-screen bg-background text-foreground selection:bg-accent selection:text-background\"\n    >\n      <AnimatedNoise opacity={0.025} />\n      <div className=\"grid-bg fixed inset-0 opacity-[0.18] pointer-events-none\" aria-hidden=\"true\" />\n\n      {/* ── Top Nav ──────────────────────────────────────────────────────── */}\n      <nav className=\"relative z-50 flex items-center justify-between px-6 py-6 md:px-12 border-b border-border/25 backdrop-blur-md bg-background/50\">\n        <div className=\"flex items-center gap-4\">\n          <span className=\"font-mono text-[10px] uppercase tracking-[0.4em] text-accent font-bold\">\n            Rapid3\n          </span>\n          <span className=\"h-px w-8 bg-border/50\" />\n          <span className=\"font-mono text-[10px] uppercase tracking-[0.4em] text-muted-foreground/80\">\n            Operative Interface\n          </span>\n        </div>\n        <Link\n          href=\"/\"\n          className=\"font-mono text-[10px] uppercase tracking-[0.3em] text-muted-foreground/70 hover:text-accent transition-colors duration-300\"\n        >\n          Logout // Disconnect\n        </Link>\n      </nav>\n\n      <div className=\"relative z-10 max-w-7xl mx-auto px-6 py-16 md:px-12 md:py-24\">\n\n        {/* ── Header ───────────────────────────────────────────────────────── */}\n        <header className=\"dashboard-header mb-20 max-w-2xl\">\n          <span className=\"font-mono text-[10px] uppercase tracking-[0.5em] text-accent block mb-4\">\n            Command Center\n          </span>\n          <h1 className=\"font-[var(--font-bebas)] text-7xl md:text-9xl tracking-tighter leading-[0.8] mb-8 text-foreground\">\n            DASHBOARD\n          </h1>\n          <p className=\"font-mono text-sm text-muted-foreground/85 leading-relaxed max-w-md\">\n            Active defensive layers are online. Deploy localized intelligence across multiple threat vectors.\n          </p>\n        </header>\n\n        {/* ── Analytics Strip ──────────────────────────────────────────────── */}\n        <div className=\"analytics-strip\">\n          <AnalyticsStrip\n            analysisCount={analysisCount}\n            threatCount={threatCount}\n            cleanCount={cleanCount}\n          />\n          <ChannelStatus results={channelStatuses} />\n        </div>\n\n        {/* ── Analysis Sections ─────────────────────────────────────────────── */}\n        <div className=\"grid grid-cols-1 lg:grid-cols-2 gap-x-24 gap-y-32\">\n\n          {/* 01 — SMS */}\n          <section className=\"dashboard-section group relative\">\n            <SectionHeader\n              index=\"01\"\n              title=\"SMS Analysis\"\n              description=\"Detect phishing patterns and malicious intent in mobile communications.\"\n            />\n            <div className=\"space-y-6\">\n              <div className=\"relative\">\n                <Input\n                  value={smsText}\n                  onChange={(e) => setSmsText(e.target.value)}\n                  onKeyDown={(e) => e.key === \"Enter\" && handleSms()}\n                  placeholder=\"Enter SMS content for threat vectoring...\"\n                  className={INPUT_CLS}\n                />\n                <div className=\"absolute bottom-0 left-0 h-[2px] w-0 bg-accent transition-all duration-700 group-focus-within:w-full\" />\n              </div>\n              <div className=\"flex justify-end\">\n                <ExecuteButton onClick={handleSms} loading={smsLoading} disabled={!smsText.trim()} />\n              </div>\n              {smsError && <ErrorBlock message={smsError} />}\n              {smsResult && <AnalysisResult data={smsResult} />}\n            </div>\n            <div className=\"absolute -inset-8 -z-10 bg-accent/[0.025] opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none\" />\n          </section>\n\n          {/* 02 — Email */}\n          <section className=\"dashboard-section group relative\">\n            <SectionHeader\n              index=\"02\"\n              title=\"Email Analysis\"\n              description=\"Deep packet inspection of SMTP artifacts and social engineering markers.\"\n            />\n            <div className=\"space-y-6\">\n              <div className=\"relative\">\n                <Input\n                  value={emailSender}\n                  onChange={(e) => setEmailSender(e.target.value)}\n                  placeholder=\"Sender address...\"\n                  className={INPUT_CLS}\n                />\n                <div className=\"absolute bottom-0 left-0 h-[2px] w-0 bg-accent transition-all duration-700 group-focus-within:w-full\" />\n              </div>\n              <div className=\"relative\">\n                <Input\n                  value={emailSubject}\n                  onChange={(e) => setEmailSubject(e.target.value)}\n                  placeholder=\"Subject line...\"\n                  className={INPUT_CLS}\n                />\n              </div>\n              <div className=\"relative\">\n                <Input\n                  value={emailBody}\n                  onChange={(e) => setEmailBody(e.target.value)}\n                  placeholder=\"Paste email body or headers...\"\n                  className={INPUT_CLS}\n                />\n              </div>\n              <div className=\"flex justify-end\">\n                <ExecuteButton\n                  onClick={handleEmail}\n                  loading={emailLoading}\n                  disabled={!emailSender.trim() || !emailBody.trim()}\n                />\n              </div>\n              {emailError && <ErrorBlock message={emailError} />}\n              {emailResult && <AnalysisResult data={emailResult} />}\n            </div>\n            <div className=\"absolute -inset-8 -z-10 bg-accent/[0.025] opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none\" />\n          </section>\n\n          {/* 03 — URL */}\n          <section className=\"dashboard-section group relative\">\n            <SectionHeader\n              index=\"03\"\n              title=\"URL Analysis\"\n              description=\"Real-time domain reputation and recursive redirect tracing.\"\n            />\n            <div className=\"space-y-6\">\n              <div className=\"relative\">\n                <Input\n                  value={urlValue}\n                  onChange={(e) => setUrlValue(e.target.value)}\n                  onKeyDown={(e) => e.key === \"Enter\" && handleUrl()}\n                  placeholder=\"https://\"\n                  className={INPUT_CLS}\n                />\n                <div className=\"absolute bottom-0 left-0 h-[2px] w-0 bg-accent transition-all duration-700 group-focus-within:w-full\" />\n              </div>\n              <div className=\"flex justify-end\">\n                <ExecuteButton onClick={handleUrl} loading={urlLoading} disabled={!urlValue.trim()} />\n              </div>\n              {urlError && <ErrorBlock message={urlError} />}\n              {urlResult && <AnalysisResult data={urlResult} />}\n            </div>\n            <div className=\"absolute -inset-8 -z-10 bg-accent/[0.025] opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none\" />\n          </section>\n\n          {/* 04 — Voice */}\n          <section className=\"dashboard-section group relative\">\n            <SectionHeader\n              index=\"04\"\n              title=\"Voice Analysis\"\n              description=\"ResNetBiLSTM analysis for synthetic voice and deepfake detection.\"\n            />\n            <div className=\"space-y-6\">\n              <FileInputRow\n                file={voiceFile}\n                placeholder=\"Upload audio sample...\"\n                accept=\"audio/*\"\n                onFile={(f) => { setVoiceFile(f); setVoiceResult(null); setVoiceError(null) }}\n              />\n              <div className=\"flex justify-end\">\n                <ExecuteButton onClick={handleVoice} loading={voiceLoading} disabled={!voiceFile} />\n              </div>\n              {voiceError && <ErrorBlock message={voiceError} />}\n              {voiceResult && <AnalysisResult data={voiceResult} />}\n            </div>\n            <div className=\"absolute -inset-8 -z-10 bg-accent/[0.025] opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none\" />\n          </section>\n\n          {/* 05 — Attachment */}\n          <section className=\"dashboard-section group relative\">\n            <SectionHeader\n              index=\"05\"\n              title=\"File Analysis\"\n              description=\"YARA-based signature matching and behavioral sandbox analysis.\"\n            />\n            <div className=\"space-y-6\">\n              <FileInputRow\n                file={attachFile}\n                placeholder=\"Select artifact for scanning...\"\n                onFile={(f) => { setAttachFile(f); setAttachResult(null); setAttachError(null) }}\n              />\n              <div className=\"flex justify-end\">\n                <ExecuteButton onClick={handleAttachment} loading={attachLoading} disabled={!attachFile} />\n              </div>\n              {attachError && <ErrorBlock message={attachError} />}\n              {attachResult && <AnalysisResult data={attachResult} />}\n            </div>\n            <div className=\"absolute -inset-8 -z-10 bg-accent/[0.025] opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none\" />\n          </section>\n\n        </div>\n\n        {/* 